import React, { useState, useRef, useEffect } from "react";

/* ============================================================
   onote 🐶 — カードノートアプリ (Artifactプレビュー版)
   - 無限キャンバス × カード(テキスト/画像/PDF)
   - カード内の文字・画像も「子カード」: 移動/拡縮/接続/複製/
     削除/外に出して独立カード化 がすべて可能
   - 連結チェーンの1枚目をダブルタップでまとめ/展開
   - 資料箱(全ノート共有) / 共有(他ノートへ送信)
   ============================================================ */

