// リッチテキスト編集: 範囲選択して色・フォントを部分適用できる contentEditable
// 値は runs [{text,color?,font?}] で保持。onApplyで現在の選択範囲に属性を当てる
function RichEditable({ initialRuns, initialText, baseColor, baseFont, fontSize, style, registerApply }) {
  const ref = React.useRef(null);
  const runsRef = React.useRef(
    (initialRuns && initialRuns.length) ? initialRuns.map((r) => ({ ...r }))
      : [{ text: initialText || "" }]
  );

  // runs から DOM(spanの集合)を構築
  const render = () => {
    const el = ref.current;
    if (!el) return;
    el.innerHTML = "";
    runsRef.current.forEach((r) => {
      const span = document.createElement("span");
      span.textContent = r.text;
      if (r.color) span.style.color = r.color;
      if (r.font) span.style.fontFamily = fontCss(r.font);
      span.dataset.color = r.color || "";
      span.dataset.font = r.font || "";
      el.appendChild(span);
    });
    if (!runsRef.current.length || runsRef.current.every((r) => !r.text)) {
      el.innerHTML = "";
    }
  };

  React.useEffect(() => { render(); /* 初回のみ */ }, []);

  // DOM → runs(各テキストノードを runs 化)。文字ごとの属性を集約
  const readChars = () => {
    const el = ref.current;
    const chars = [];
    el.childNodes.forEach((node) => {
      const color = node.dataset ? node.dataset.color : "";
      const font = node.dataset ? node.dataset.font : "";
      const txt = node.textContent || "";
      for (const c of txt) chars.push({ ch: c, color, font });
    });
    return chars;
  };
  const charsToRuns = (chars) => {
    const runs = [];
    chars.forEach((c) => {
      const last = runs[runs.length - 1];
      if (last && (last.color || "") === (c.color || "") && (last.font || "") === (c.font || "")) {
        last.text += c.ch;
      } else {
        runs.push({ text: c.ch, color: c.color || undefined, font: c.font || undefined });
      }
    });
    return runs;
  };

  // 現在の選択範囲(文字インデックス)を取得
  const getSelRange = () => {
    const el = ref.current;
    const sel = window.getSelection();
    if (!sel || sel.rangeCount === 0) return null;
    const range = sel.getRangeAt(0);
    if (!el.contains(range.startContainer)) return null;
    const idxOf = (container, offset) => {
      let count = 0, found = -1;
      const walk = (node) => {
        if (found >= 0) return;
        if (node.nodeType === 3) {
          if (node === container) { found = count + offset; return; }
          count += node.textContent.length;
        } else {
          node.childNodes.forEach(walk);
        }
      };
      el.childNodes.forEach(walk);
      return found < 0 ? count : found;
    };
    const a = idxOf(range.startContainer, range.startOffset);
    const b = idxOf(range.endContainer, range.endOffset);
    return [Math.min(a, b), Math.max(a, b)];
  };

  // 選択範囲に属性を適用
  const apply = (attr) => {
    const sel = getSelRange();
    const chars = readChars();
    if (!sel || sel[0] === sel[1]) return false; // 範囲未選択
    for (let i = sel[0]; i < sel[1] && i < chars.length; i++) {
      if (attr.color !== undefined) chars[i].color = attr.color;
      if (attr.font !== undefined) chars[i].font = attr.font;
    }
    runsRef.current = charsToRuns(chars);
    render();
    return true;
  };

  // 現在のrunsを返す(確定時に親が読む)
  const getRuns = () => {
    const chars = readChars();
    return charsToRuns(chars);
  };

  React.useEffect(() => {
    if (registerApply) registerApply({ apply, getRuns });
  });

  return (
    <div
      ref={ref}
      contentEditable
      suppressContentEditableWarning
      data-empty-text="テキストを入力"
      onInput={() => { runsRef.current = getRuns(); }}
      style={{
        ...style,
        outline: "none", whiteSpace: "pre-wrap", cursor: "text",
        color: baseColor, fontFamily: fontCss(baseFont), fontSize,
      }}
    />
  );
}

const Toast = ({ msg }) => !msg ? null : (
  <div style={{
    position: "fixed", bottom: 100, left: "50%", transform: "translateX(-50%)", zIndex: 300,
    background: "rgba(63,71,80,0.94)", color: "#fff", padding: "10px 20px", borderRadius: 20,
    fontSize: 13, boxShadow: "0 4px 16px rgba(0,0,0,0.4)", maxWidth: "85%", textAlign: "center",
  }}>{msg}</div>
);

/* ============================================================
   カードエディタ(全画面)
   - 子カード: 選択/ドラッグ移動/角で拡縮/右の○から接続/
     長押しで複製・削除/タップで文字編集/ダブルタップで開く/
     ステージの外へドラッグ → 独立カードとして外に出す
   ============================================================ */
function CardEditor({ cardId, cards, patchCard, addCards, removeDeep, detachChild, pushEdit, depth, onClose, showToast, onUndo = () => {}, onRedo = () => {}, chainIds = null, onNavigate = () => {} }) {
  const card = cards.find((c) => c.id === cardId);
  const kids = childrenOf(cards, cardId);
  const isChild = card && card.parentId != null;

  const [mode, setMode] = useState("move"); // move | pen | eraser | select
  const [penColor, setPenColor] = useState("#3f4750");
  const DEFAULT_SLOTS = ["#3f4750", "#e3a8bd", "#8fb6cc", "#a99bd1", "#8fbfa4"];
  const [slots, setSlots] = useState(() => {
    try { const r = JSON.parse(localStorage.getItem("onote:slots")); if (Array.isArray(r) && r.length === 5) return r; } catch (e) {}
    return [...DEFAULT_SLOTS];
  });
  const [activeSlot, setActiveSlot] = useState(0);
  const saveSlots = (arr) => { setSlots(arr); try { localStorage.setItem("onote:slots", JSON.stringify(arr)); } catch (e) {} };
  // スロットの色を更新して適用
  const setSlotColor = (i, color) => {
    const arr = slots.map((c, j) => (j === i ? color : c));
    saveSlots(arr); setActiveSlot(i); applyColor(color);
  };
  // スポイト(画面上の色を吸い取る)
  const pickEyedropper = async () => {
    if (window.EyeDropper) {
      try {
        const res = await new window.EyeDropper().open();
        if (res && res.sRGBHex) setSlotColor(activeSlot, res.sRGBHex);
      } catch (e) { /* キャンセル */ }
    } else {
      showToast("お使いの環境ではスポイトが使えません(色ボタンから選べます)");
    }
  };
  const [penWidth, setPenWidth] = useState(6);
  const [penType, setPenType] = useState("pen"); // pen | pencil | marker
  const [penOpen, setPenOpen] = useState(false); // ペン設定パネル
  const PEN_WIDTHS = [2, 4, 6, 10, 16];          // 5段階の太さ
  const liveCanvas = useRef(null);   // 描画中だけ使う高速キャンバス(ラグ防止)
  const eraseRef = useRef(null);     // 消しゴムでドラッグ中
  const [lassoPath, setLassoPath] = useState(null);     // 範囲選択の軌跡(フリーハンド)
  const [selStrokeIds, setSelStrokeIds] = useState([]); // 選択済みストロークID
  const lassoRef = useRef(null);     // 矩形ドラッグ中
  const strokeDrag = useRef(null);   // 選択ストロークの移動
  const strokeResize = useRef(null); // 選択ストロークの拡大縮小
  const [selected, setSelected] = useState(null);   // 子カードid
  const [inlineEdit, setInlineEdit] = useState(null); // {id, value} 子テキスト編集
  const [selfEdit, setSelfEdit] = useState(null);     // {value} このカード自身の文字編集
  const [childMenu, setChildMenu] = useState(null);   // {id, vx, vy}
  const [connectLine, setConnectLine] = useState(null);
  const [vp, setVp] = useState({ w: window.innerWidth, h: window.innerHeight });
  const [eview, setEview] = useState({ x: 0, y: 0, zoom: 1 }); // エディタの表示(パン+ズーム)
  const zoom = eview.zoom; // 互換用
  const setZoom = (fn) => setEview((v) => ({ ...v, zoom: typeof fn === "function" ? fn(v.zoom) : fn }));
  const ePinch = useRef(null);   // エディタ2本指(ズーム+パン)
  const ePan = useRef(null);     // エディタ1本指パン(背景)
  const stageBox = useRef(null);
  const scrollBox = useRef(null);
  const pointers = useRef(new Map());   // 現在触れている指
  const barRef = useRef(null);
  const [barH, setBarH] = useState(58);
  const swipeRef = useRef(null);
  const richApi = useRef(null);
  const drawing = useRef(null);
  const dragChild = useRef(null);
  const resizeChild = useRef(null);
  const connRef = useRef(null);
  const longPress = useRef(null);
  const tapRef = useRef({ t: 0, id: null });
  const imgInput = useRef(null);
  // ビューポート背景の1本指パン(ステージ外をドラッグ)
  const vpDown = (e) => {
    if (stageBox.current && stageBox.current.contains(e.target)) return; // ステージ上は通常操作
    ePan.current = { sx: e.clientX, sy: e.clientY, ex: eview.x, ey: eview.y };
    try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {}
  };
  const vpMove = (e) => {
    if (!ePan.current) return;
    setEview((v) => ({ ...v, x: ePan.current.ex + (e.clientX - ePan.current.sx), y: ePan.current.ey + (e.clientY - ePan.current.sy) }));
  };
  const vpUp = () => { ePan.current = null; };
  // 中央基準でズーム(ボタン用・アニメ付き)
  const zoomCenter = (factor) => {
    setEview((v) => {
      const nz = Math.min(4, Math.max(0.3, v.zoom * factor));
      const k = nz / v.zoom;
      return { x: v.x * k, y: v.y * k, zoom: nz, anim: true };
    });
  };
  useEffect(() => {
    if (eview.anim) {
      const t = setTimeout(() => setEview((v) => ({ ...v, anim: false })), 230);
      return () => clearTimeout(t);
    }
  }, [eview.anim, eview.zoom]);
  const emt = useRef({ count: 0, max: 0, t: 0, moved: false });
  const emtDown = (e) => {
    const m = emt.current;
    m.count++;
    if (m.count === 1) { m.t = Date.now(); m.max = 1; m.moved = false; }
    m.max = Math.max(m.max, m.count);
  };
  const emtUp = () => {
    const m = emt.current;
    m.count = Math.max(0, m.count - 1);
    if (m.count === 0) {
      const quick = Date.now() - m.t < 500;
      const busy = !!drawing.current || !!ePinch.current || !!inlineEdit || !!selfEdit;
      if (quick && !busy && !m.moved) {
        if (m.max === 2) onUndo();
        else if (m.max === 3) onRedo();
      }
      emt.current = { count: 0, max: 0, t: 0, moved: false };
    }
  };

  useEffect(() => {
    const f = () => setVp({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener("resize", f);
    return () => window.removeEventListener("resize", f);
  }, []);
  const barWatch = `${penOpen}|${mode}|${selected}|${inlineEdit && inlineEdit.id}`;
  useEffect(() => {
    // ツールバー(複数段)の合計高さを毎回測ってステージ計算に反映
    const root = barRef.current && barRef.current.parentElement;
    if (root) {
      let h = 0;
      [...root.children].forEach((c) => { if (c !== scrollBox.current) h += c.offsetHeight; });
      setBarH(h);
    } else if (barRef.current) {
      setBarH(barRef.current.offsetHeight);
    }
  }, [vp.w, vp.h, card && card.text, isChild, barWatch]);

  if (!card) return null;

  const baseS = Math.min((vp.w - 20) / STAGE_W, (vp.h - barH - 20) / STAGE_H);
  const s = baseS * zoom;            // 座標変換用(getBoundingClientRectは変換後のサイズを返す)
  const dispW = STAGE_W * baseS, dispH = STAGE_H * baseS; // 素の表示サイズ(transformでzoom適用)

  const toStage = (e) => {
    const r = stageBox.current.getBoundingClientRect();
    return [(e.clientX - r.left) / s, (e.clientY - r.top) / s];
  };
  const hitChild = (x, y) => [...kids].reverse().find((ch) =>
    x >= ch.x && x <= ch.x + ch.w && y >= ch.y && y <= ch.y + ch.h);

  // 消しゴム: (x,y)付近を通るストロークを消す
  const eraseAt = (x, y) => {
    if (!eraseRef.current) return;
    const R = Math.max(14, penWidth + 10); // 消しゴム半径(STAGE座標)
    const hit = card.strokes.find((s) => {
      if (eraseRef.current.erased.has(s.id)) return false;
      return s.points.some(([px, py]) => Math.hypot(px - x, py - y) <= R + (s.width || 4) / 2);
    });
    if (hit) {
      eraseRef.current.erased.add(hit.id);
      patchCard(card.id, { strokes: card.strokes.filter((s) => s.id !== hit.id) });
    }
  };

  /* ---- 範囲選択(手書きストローク) ---- */
  const strokeBBox = (ids) => {
    const ss = card.strokes.filter((s) => ids.includes(s.id));
    if (!ss.length) return null;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    ss.forEach((s) => s.points.forEach(([px, py]) => {
      minX = Math.min(minX, px); minY = Math.min(minY, py);
      maxX = Math.max(maxX, px); maxY = Math.max(maxY, py);
    }));
    return { minX, minY, maxX, maxY };
  };
  const selBBox = strokeBBox(selStrokeIds);
  const transformSelected = (fn) => {
    patchCard(card.id, { strokes: card.strokes.map((s) =>
      selStrokeIds.includes(s.id) ? { ...s, points: s.points.map(fn) } : s) });
  };

  // 上部の色選択: ペン色に加えて、
  //  - このカード自身がテキストカードなら card.textColor を変更
  //  - 子テキストをインライン編集中ならその子の textColor を変更
  //  - 子テキストを選択中ならその子の textColor を変更
  const applyColor = (c) => {
    setPenColor(c);
    // インライン編集中で範囲選択があれば、その部分だけ色変更
    if (inlineEdit && richApi.current && richApi.current.apply({ color: c })) return;
    if (typeof card.text === "string") {
      patchCard(card.id, { textColor: c });
    } else if (inlineEdit) {
      patchCard(inlineEdit.id, { textColor: c });
    } else if (selected) {
      const sel = cards.find((x) => x.id === selected);
      if (sel && typeof sel.text === "string") patchCard(sel.id, { textColor: c });
    }
  };

  const commitInline = () => {
    if (!inlineEdit) return;
    const runs = richApi.current ? richApi.current.getRuns() : null;
    const plain = runsToText(runs).replace(/\s+$/, "");
    if (plain === "") removeDeep(inlineEdit.id);
    else {
      const simple = runs && runs.length === 1 && !runs[0].color && !runs[0].font;
      patchCard(inlineEdit.id, simple ? { text: plain, runs: null } : { text: plain, runs });
    }
    setInlineEdit(null);
  };
  const commitSelf = () => {
    if (!selfEdit) return;
    patchCard(card.id, { text: selfEdit.value });
    setSelfEdit(null);
  };

  /* ---- ステージ操作 ---- */
  const dist2 = () => {
    const ps = [...pointers.current.values()];
    return Math.hypot(ps[0].x - ps[1].x, ps[0].y - ps[1].y);
  };
  const center2 = () => {
    const ps = [...pointers.current.values()];
    return { x: (ps[0].x + ps[1].x) / 2, y: (ps[0].y + ps[1].y) / 2 };
  };
  const down = (e) => {
    pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    if (pointers.current.size === 2) {
      // 2本指: ズーム+パン開始。進行中の描画・ドラッグを破棄
      clearTimeout(longPress.current);
      if (drawing.current) {
        drawing.current = null;
        const cv = liveCanvas.current; if (cv) cv.getContext("2d").clearRect(0, 0, cv.width, cv.height);
      }
      eraseRef.current = null;
      dragChild.current = null;
      resizeChild.current = null;
      lassoRef.current = null; setLassoPath(null);
      const c = center2();
      ePinch.current = { dist: dist2(), zoom: eview.zoom, cx: c.x, cy: c.y, ex: eview.x, ey: eview.y, lastc: c };
      emt.current.moved = true;
      try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {}
      return;
    }
    if (pointers.current.size > 2) return;
    if (inlineEdit) { commitInline(); return; }
    if (selfEdit) { commitSelf(); return; }
    setChildMenu(null);
    const [x, y] = toStage(e);
    if (mode === "pen") {
      // 描画中はstateを触らず、専用canvasに直接描く(ラグ防止)
      const w = penType === "marker" ? Math.max(penWidth * 2.4, 16) : penWidth;
      drawing.current = { id: uid(), color: penColor, kind: penType, width: w, points: [[x, y]] };
      const cv = liveCanvas.current;
      if (cv) {
        const ctx = cv.getContext("2d");
        ctx.lineCap = "round"; ctx.lineJoin = "round";
        ctx.strokeStyle = penColor;
        ctx.globalAlpha = penType === "marker" ? 0.3 : (penType === "pencil" ? 0.95 : 1);
        ctx.lineWidth = w * (dispW / STAGE_W);
        ctx.beginPath();
        ctx.moveTo(x * (dispW / STAGE_W), y * (dispH / STAGE_H));
      }
      e.currentTarget.setPointerCapture(e.pointerId);
      return;
    }
    if (mode === "eraser") {
      eraseRef.current = { erased: new Set() };
      eraseAt(x, y);
      e.currentTarget.setPointerCapture(e.pointerId);
      return;
    }
    if (mode === "select") {
      // すでに選択があり、その範囲内を押したら移動開始
      if (selBBox && x >= selBBox.minX - 12 && x <= selBBox.maxX + 12 && y >= selBBox.minY - 12 && y <= selBBox.maxY + 12) {
        strokeDrag.current = { sx: x, sy: y };
      } else {
        // 新しく矩形選択を開始
        setSelStrokeIds([]);
        lassoRef.current = { pts: [[x, y]] };
        setLassoPath([[x, y]]);
      }
      e.currentTarget.setPointerCapture(e.pointerId);
      return;
    }
    const ch = hitChild(x, y);
    if (ch) {
      setSelected(ch.id);
      dragChild.current = { id: ch.id, dx: x - ch.x, dy: y - ch.y, moved: false, sx: e.clientX, sy: e.clientY };
      e.currentTarget.setPointerCapture(e.pointerId);
      longPress.current = setTimeout(() => {
        if (dragChild.current && !dragChild.current.moved) {
          setChildMenu({ id: ch.id, vx: e.clientX, vy: e.clientY });
          dragChild.current = null;
        }
      }, 550);
    } else {
      setSelected(null);
      // チェーンの一部なら、空き場所からの横スワイプで前後カードへ移動できるよう開始点を記録
      if (mode === "move" && chainIds && chainIds.length >= 2) {
        swipeRef.current = { sx: e.clientX, sy: e.clientY };
        try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {}
      }
    }
  };
  const move = (e) => {
    if (pointers.current.has(e.pointerId)) pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    if (ePinch.current && pointers.current.size >= 2) {
      emt.current.moved = true;
      const bp = ePinch.current;
      const d = dist2();
      const c = center2();
      const r = scrollBox.current.getBoundingClientRect();
      // ビューポート中心からの焦点オフセット(transformはcenter基準)
      const fx0 = bp.cx - (r.left + r.width / 2);
      const fy0 = bp.cy - (r.top + r.height / 2);
      const fx1 = c.x - (r.left + r.width / 2);
      const fy1 = c.y - (r.top + r.height / 2);
      const ratio = bp.dist > 0 ? d / bp.dist : 1;
      const nz = Math.min(4, Math.max(0.3, bp.zoom * ratio));
      // 焦点を固定しつつズーム、さらに2本指の中心移動でパン
      const nx = fx1 - (fx0 - bp.ex) * (nz / bp.zoom);
      const ny = fy1 - (fy0 - bp.ey) * (nz / bp.zoom);
      setEview({ x: nx, y: ny, zoom: nz });
      return;
    }
    if (lassoRef.current) {
      const [x, y] = toStage(e);
      lassoRef.current.pts.push([x, y]);
      setLassoPath([...lassoRef.current.pts]);
      return;
    }
    if (strokeDrag.current) {
      const [x, y] = toStage(e);
      const dx = x - strokeDrag.current.sx, dy = y - strokeDrag.current.sy;
      strokeDrag.current.sx = x; strokeDrag.current.sy = y;
      transformSelected(([px, py]) => [px + dx, py + dy]);
      return;
    }
    if (strokeResize.current) {
      const [x, y] = toStage(e);
      const br = strokeResize.current;
      const sx = (x - br.ax) / (br.bx - br.ax || 1);
      const sy = (y - br.ay) / (br.by - br.ay || 1);
      const k = Math.max(0.1, Math.min(sx, sy)); // 縦横比維持
      transformSelected(([px, py]) => [br.ax + (px - br.ax) * (k / br.lastK), br.ay + (py - br.ay) * (k / br.lastK)]);
      br.lastK = k;
      return;
    }
    if (drawing.current) {
      const [x, y] = toStage(e);
      // 中間点を取得して滑らかに(coalesced events対応)
      const evs = (e.getCoalescedEvents && e.getCoalescedEvents().length) ? e.getCoalescedEvents() : [e];
      const cv = liveCanvas.current;
      const ctx = cv && cv.getContext("2d");
      const kx = dispW / STAGE_W, ky = dispH / STAGE_H;
      evs.forEach((ev) => {
        const [px, py] = toStage(ev);
        drawing.current.points.push([px, py]);
        if (ctx) { ctx.lineTo(px * kx, py * ky); }
      });
      if (ctx) { ctx.stroke(); }
      return;
    }
    if (eraseRef.current) {
      const [x, y] = toStage(e);
      eraseAt(x, y);
      return;
    }
    if (resizeChild.current) {
      const [x, y] = toStage(e);
      const ch = cards.find((c) => c.id === resizeChild.current.id);
      if (ch) {
        const nw = Math.max(60, x - ch.x), nh = Math.max(50, y - ch.y);
        const patch = { w: nw, h: nh };
        // テキストカードは高さの拡大率に合わせて文字サイズも拡大縮小
        if (typeof ch.text === "string" && ch.h > 0) {
          patch.fontSize = Math.max(10, Math.round((ch.fontSize || 46) * (nh / ch.h)));
        }
        patchCard(ch.id, patch);
      }
      return;
    }
    if (dragChild.current) {
      const d = dragChild.current;
      if (!d.moved && Math.hypot(e.clientX - d.sx, e.clientY - d.sy) < 7) return;
      d.moved = true;
      clearTimeout(longPress.current);
      const dch = cards.find((c) => c.id === d.id);
      if (dch && dch.pinned) return; // ピン留め中は移動しない
      const [x, y] = toStage(e);
      patchCard(d.id, { x: x - d.dx, y: y - d.dy });
    }
  };
  const up = (e) => {
    pointers.current.delete(e.pointerId);
    if (ePinch.current) {
      if (pointers.current.size < 2) ePinch.current = null;
      return; // ピンチの指離しはタップ扱いしない
    }
    // 手書き確定: ここで初めてstateに反映し、ライブcanvasを消す
    if (drawing.current) {
      const st = drawing.current;
      drawing.current = null;
      if (st.points.length >= 1) patchCard(card.id, { strokes: [...card.strokes, st] });
      const cv = liveCanvas.current;
      if (cv) cv.getContext("2d").clearRect(0, 0, cv.width, cv.height);
      return;
    }
    if (eraseRef.current) {
      const ids = eraseRef.current.erased;
      eraseRef.current = null;
      if (ids.size) patchCard(card.id, { strokes: card.strokes.filter((s) => !ids.has(s.id)) });
      return;
    }
    // 横スワイプでチェーンの前後カードへ移動
    if (swipeRef.current) {
      const dx = e.clientX - swipeRef.current.sx;
      const dy = e.clientY - swipeRef.current.sy;
      swipeRef.current = null;
      if (Math.abs(dx) > 60 && Math.abs(dx) > Math.abs(dy) * 1.5 && chainIds) {
        const idx = chainIds.indexOf(cardId);
        if (dx < 0 && idx < chainIds.length - 1) { onNavigate(chainIds[idx + 1]); return; }
        if (dx > 0 && idx > 0) { onNavigate(chainIds[idx - 1]); return; }
      }
    }
    // 範囲選択の確定(フリーハンドで囲んだ内側)
    if (lassoRef.current) {
      const poly = lassoRef.current.pts;
      lassoRef.current = null;
      setLassoPath(null);
      if (poly && poly.length >= 3) {
        const inPoly = (px, py) => {
          let inside = false;
          for (let i = 0, j = poly.length - 1; i < poly.length; j = i++) {
            const xi = poly[i][0], yi = poly[i][1], xj = poly[j][0], yj = poly[j][1];
            if (((yi > py) !== (yj > py)) && (px < ((xj - xi) * (py - yi)) / (yj - yi) + xi)) inside = !inside;
          }
          return inside;
        };
        const sel = card.strokes.filter((st) => {
          const n = st.points.filter(([px, py]) => inPoly(px, py)).length;
          return n > 0 && n >= st.points.length * 0.5;
        }).map((st) => st.id);
        setSelStrokeIds(sel);
        if (!sel.length) showToast("手書きの線をぐるっと囲ってね");
      }
      return;
    }
    if (strokeDrag.current) { strokeDrag.current = null; return; }
    if (strokeResize.current) { strokeResize.current = null; return; }
    clearTimeout(longPress.current);
    drawing.current = null;
    resizeChild.current = null;
    const d = dragChild.current;
    dragChild.current = null;
    if (!d) return;
    const ch = cards.find((c) => c.id === d.id);
    if (!ch) return;
    if (d.moved) {
      // 中心がステージの外 → 独立カードとして外に出す
      const cx = ch.x + ch.w / 2, cy = ch.y + ch.h / 2;
      if (cx < 0 || cx > STAGE_W || cy < 0 || cy > STAGE_H) {
        detachChild(ch.id);
        setSelected(null);
        showToast("カードを外に出しました(キャンバスに独立カードとして置かれます)");
      }
      return;
    }
    // タップ: ダブルタップ→開く / テキスト子はシングルで文字編集
    const now = Date.now();
    if (tapRef.current.id === ch.id && now - tapRef.current.t < 320) {
      tapRef.current = { t: 0, id: null };
      pushEdit(ch.id);
    } else {
      tapRef.current = { t: now, id: ch.id };
      if (typeof ch.text === "string") {
        const target = ch.id;
        setTimeout(() => {
          if (tapRef.current.id === target) setInlineEdit({ id: target, value: cards.find((c) => c.id === target)?.text || "" });
        }, 330);
      }
    }
  };

  /* ---- 子カードの接続 ---- */
  const connDown = (ch) => (e) => {
    e.stopPropagation();
    connRef.current = { fromId: ch.id };
    const [x, y] = toStage(e);
    setConnectLine({ x, y });
    e.currentTarget.setPointerCapture(e.pointerId);
  };
  const connMove = () => (e) => {
    if (!connRef.current) return;
    const [x, y] = toStage(e);
    setConnectLine({ x, y });
  };
  const connUp = () => (e) => {
    if (!connRef.current) return;
    const from = cards.find((c) => c.id === connRef.current.fromId);
    const [x, y] = toStage(e);
    const target = hitChild(x, y);
    connRef.current = null;
    setConnectLine(null);
    if (!target || !from || target.id === from.id) return;
    if (from.next) { showToast("1枚のカードから出せる接続は1本までです"); return; }
    if (buildIncoming(kids)[target.id]) { showToast("そのカードにはすでに接続が入っています"); return; }
    if (chainFrom(kids, target.id).some((c) => c.id === from.id)) { showToast("循環する接続はできません"); return; }
    patchCard(from.id, { next: target.id });
  };

  const addChildText = () => {
    const ch = {
      ...newCard("text", STAGE_W / 2 - 170, STAGE_H / 2 - 70, { parentId: card.id }),
      w: 340, h: 140, color: "transparent", text: "", textColor: penColor, fontSize: 46,
    };
    addCards([ch]);
    setMode("move");
    setSelected(ch.id);
    setInlineEdit({ id: ch.id, value: "" });
  };
  const addChildImage = (file) => {
    const rd = new FileReader();
    rd.onload = () => {
      addCards([{ ...newCard("image", STAGE_W / 2 - 160, STAGE_H / 2 - 110, { parentId: card.id }), w: 320, h: 220, src: rd.result }]);
    };
    rd.readAsDataURL(file);
  };

  const Icon = ({ name, size = 20, color = "currentColor" }) => {
    const sw = 1.7;
    const common = { width: size, height: size, viewBox: "0 0 24 24", fill: "none", stroke: color, strokeWidth: sw, strokeLinecap: "round", strokeLinejoin: "round" };
    const paths = {
      hand: <><path d="M9 11V5.5a1.5 1.5 0 0 1 3 0V11" /><path d="M12 11V4.5a1.5 1.5 0 0 1 3 0V11" /><path d="M15 11V6.5a1.5 1.5 0 0 1 3 0V14a6 6 0 0 1-6 6h-1.5a5 5 0 0 1-4-2l-3-4a1.6 1.6 0 0 1 2.5-2L9 13V6a1.5 1.5 0 0 1 3 0" /></>,
      pen: <><path d="M16.5 4.5l3 3L8 19l-4 1 1-4z" /><path d="M14.5 6.5l3 3" /></>,
      lasso: <><path d="M4 11a8 4 0 1 1 12 3.5" strokeDasharray="2.5 2.5" /><path d="M7 16.5a2 2 0 1 0 1.8-2.8" /><path d="M7 18.5v2" /></>,
      eraser: <><path d="M8 18h11" /><path d="M6.5 15.5l6-6 5 5-4 4H10z" /><path d="M9.5 12.5l5 5" /></>,
      textPlus: <><path d="M4 6h9" /><path d="M8.5 6v12" /><path d="M17 11v8" /><path d="M14 15h6" /></>,
      imgPlus: <><rect x="3" y="4" width="13" height="13" rx="2" /><circle cx="7.5" cy="8.5" r="1.3" /><path d="M3 14l3.5-3 3 2.5L14 9l2 2.5" /><path d="M18 14v6" /><path d="M15 17h6" /></>,
      editText: <><path d="M5 5h10" /><path d="M9.5 5v10" /><path d="M14 19l5-5 2 2-5 5h-2z" /></>,
      minus: <path d="M5 12h14" />,
      plus: <><path d="M12 5v14" /><path d="M5 12h14" /></>,
      undo: <><path d="M9 7L4 12l5 5" /><path d="M4 12h11a5 5 0 0 1 0 10h-1" /></>,
      redo: <><path d="M15 7l5 5-5 5" /><path d="M20 12H9a5 5 0 0 0 0 10h1" /></>,
      check: <path d="M5 12.5l4.5 4.5L19 6.5" />,
      back: <path d="M15 5l-7 7 7 7" />,
      dropper: <><path d="M15 4l5 5-9 9-5 1 1-5z" /><path d="M13.5 6.5l4 4" /></>,
      bigger: <><path d="M4 9V4h5" /><path d="M20 15v5h-5" /><path d="M4 4l6 6" /><path d="M20 20l-6-6" /></>,
      smaller: <><path d="M9 4H4v5" /><path d="M15 20h5v-5" /><path d="M4 4l5 5" /><path d="M20 20l-5-5" /></>,
    };
    return <svg {...common}>{paths[name]}</svg>;
  };

  const Tool = ({ active, onClick, children, title }) => (
    <button onClick={onClick} title={title} style={{
      width: 38, height: 38, borderRadius: 10, fontSize: 17, cursor: "pointer",
      border: "none",
      background: active ? "rgba(120,176,204,0.28)" : "rgba(255,255,255,0.06)",
      color: active ? "#9cc8e0" : "#d9dde2",
      flexShrink: 0, display: "inline-flex", alignItems: "center", justifyContent: "center",
      transition: "all .12s",
    }}>{children}</button>
  );

  const selectedCh = selected ? kids.find((k) => k.id === selected) : null;
  const inc = buildIncoming(kids);
  // テキスト編集対象: 自身がテキストカード or テキスト子を選択中 or インライン編集中
  const textTarget =
    (inlineEdit && kids.find((k) => k.id === inlineEdit.id)) ||
    (selectedCh && typeof selectedCh.text === "string" ? selectedCh : null) ||
    (typeof card.text === "string" ? card : null);
  const patchText = (patch) => { if (textTarget) patchCard(textTarget.id, patch); };

  return (
    <div
      onPointerDownCapture={emtDown} onPointerUpCapture={emtUp} onPointerCancelCapture={emtUp}
      style={{ position: "fixed", inset: 0, background: EDITOR_BG, zIndex: 100 + depth, display: "flex", flexDirection: "column" }}>
      <div ref={barRef} style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: 6, padding: "9px 12px", flexShrink: 0, background: "#2a2a2c", borderBottom: "1px solid #000", rowGap: 8 }}>
        <button onClick={onClose} style={{ display: "inline-flex", alignItems: "center", gap: 4, background: "none", border: "none", color: "#d9dde2", cursor: "pointer", fontSize: 13, fontWeight: 600, flexShrink: 0, padding: "8px 6px", letterSpacing: 0.5 }}><Icon name="back" size={16} /> 戻る</button>
        {depth > 1 && <span style={{ fontSize: 10, color: "#8b93a0", flexShrink: 0 }}>親へ</span>}

        {/* チェーンの前後移動 */}
        {chainIds && chainIds.length >= 2 && (() => {
          const idx = chainIds.indexOf(cardId);
          return (
            <div style={{ display: "flex", alignItems: "center", gap: 2, flexShrink: 0, background: "rgba(255,255,255,0.06)", borderRadius: 10, padding: "0 2px" }}>
              <button onClick={() => idx > 0 && onNavigate(chainIds[idx - 1])} disabled={idx <= 0}
                title="前のカード" style={{ width: 26, height: 34, border: "none", background: "none", color: idx > 0 ? "#9cc8e0" : "#555", fontSize: 16, cursor: idx > 0 ? "pointer" : "default" }}>‹</button>
              <span style={{ fontSize: 10, color: "#9cc8e0", fontWeight: 700, minWidth: 26, textAlign: "center" }}>{idx + 1}/{chainIds.length}</span>
              <button onClick={() => idx < chainIds.length - 1 && onNavigate(chainIds[idx + 1])} disabled={idx >= chainIds.length - 1}
                title="次のカード" style={{ width: 26, height: 34, border: "none", background: "none", color: idx < chainIds.length - 1 ? "#9cc8e0" : "#555", fontSize: 16, cursor: idx < chainIds.length - 1 ? "pointer" : "default" }}>›</button>
            </div>
          );
        })()}

        <div style={{ flex: 1, minWidth: 4 }} />

        {/* ツール群(選択/ペン/範囲選択/消しゴム) */}
        <div style={{ display: "flex", alignItems: "center", gap: 4, background: "rgba(0,0,0,0.25)", borderRadius: 12, padding: 3, flexShrink: 0 }}>
          <Tool active={mode === "move"} onClick={() => { setMode("move"); setSelStrokeIds([]); setLassoPath(null); }} title="選択・移動"><Icon name="hand" /></Tool>
          <Tool active={mode === "pen"} onClick={() => { setMode("pen"); setSelected(null); setSelStrokeIds([]); }} title="ペン"><Icon name="pen" /></Tool>
          <Tool active={mode === "select"} onClick={() => { setMode("select"); setSelected(null); setPenOpen(false); }} title="範囲選択"><Icon name="lasso" /></Tool>
          <Tool active={mode === "eraser"} onClick={() => { setMode("eraser"); setSelected(null); setPenOpen(false); setSelStrokeIds([]); }} title="消しゴム"><Icon name="eraser" /></Tool>
        </div>

        {/* 追加群(テキスト・画像) */}
        {!isChild && (
          <div style={{ display: "flex", alignItems: "center", gap: 4, background: "rgba(0,0,0,0.25)", borderRadius: 12, padding: 3, flexShrink: 0 }}>
            <Tool onClick={addChildText} title="テキストを追加"><Icon name="textPlus" /></Tool>
            <Tool onClick={() => imgInput.current.click()} title="画像を追加"><Icon name="imgPlus" /></Tool>
          </div>
        )}
        {typeof card.text === "string" && (
          <Tool onClick={() => setSelfEdit({ value: card.text || "" })} title="このカードの文字を編集"><Icon name="editText" /></Tool>
        )}

        {/* 色(5スロット保存式) + スポイト + ペン設定 */}
        <div style={{ display: "flex", alignItems: "center", gap: 5, background: "rgba(0,0,0,0.25)", borderRadius: 12, padding: "3px 6px", flexShrink: 0 }}>
          {slots.map((c, i) => (
            <label key={i} title="タップで使用 / 長押しで色を変更" style={{
              width: 26, height: 26, borderRadius: 13, background: c, cursor: "pointer", flexShrink: 0, position: "relative",
              border: activeSlot === i && penColor === c ? "2.5px solid #9cc8e0" : "2px solid rgba(255,255,255,0.25)",
              display: "inline-block",
            }}
              onClick={() => { setActiveSlot(i); applyColor(c); }}>
              {/* 長押し相当: このスロットのcolor inputを開くと色を再設定 */}
              <input type="color" value={c.length === 7 ? c : "#3f4750"}
                onInput={(e) => setSlotColor(i, e.target.value)}
                onClick={(e) => e.stopPropagation()}
                style={{ position: "absolute", inset: 0, opacity: 0, width: "100%", height: "100%", cursor: "pointer" }} />
            </label>
          ))}
          <button onClick={pickEyedropper} title="スポイト(画面の色を吸う)" style={{
            width: 26, height: 26, borderRadius: 13, cursor: "pointer", flexShrink: 0, border: "2px solid rgba(255,255,255,0.25)",
            background: "rgba(255,255,255,0.06)", display: "inline-flex", alignItems: "center", justifyContent: "center", color: "#d9dde2",
          }}><Icon name="dropper" size={14} /></button>
          <Tool active={penOpen} onClick={() => setPenOpen((v) => !v)} title="ペンの太さ・種類">
            <span style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", lineHeight: 1, gap: 2 }}>
              <Icon name={penType === "eraser" ? "eraser" : "pen"} size={16} />
              <span style={{ display: "inline-block", width: 14, height: Math.max(2, Math.min(penWidth, 7)), borderRadius: 4, background: "#9cc8e0", opacity: penType === "marker" ? 0.5 : 1 }} />
            </span>
          </Tool>
        </div>

        {/* ズーム */}
        <div style={{ display: "flex", alignItems: "center", gap: 2, background: "rgba(0,0,0,0.25)", borderRadius: 12, padding: 3, flexShrink: 0 }}>
          <Tool onClick={() => zoomCenter(0.8)} title="縮小"><Icon name="minus" size={18} /></Tool>
          <button onClick={() => setEview({ x: 0, y: 0, zoom: 1, anim: true })} title="100%" style={{
            minWidth: 40, height: 38, borderRadius: 10, fontSize: 11, fontWeight: 700, cursor: "pointer",
            border: "none", background: "rgba(255,255,255,0.06)", color: zoom !== 1 ? "#9cc8e0" : "#d9dde2",
          }}>{Math.round(zoom * 100)}%</button>
          <Tool onClick={() => zoomCenter(1.25)} title="拡大"><Icon name="plus" size={18} /></Tool>
        </div>

        {/* 元に戻す/やり直し */}
        <div style={{ display: "flex", alignItems: "center", gap: 2, background: "rgba(0,0,0,0.25)", borderRadius: 12, padding: 3, flexShrink: 0 }}>
          <Tool onClick={onUndo} title="ひとつ前に戻す"><Icon name="undo" size={18} /></Tool>
          <Tool onClick={onRedo} title="戻す前に戻す"><Icon name="redo" size={18} /></Tool>
        </div>

        {/* 完了 */}
        <button onClick={onClose} style={{ display: "inline-flex", alignItems: "center", gap: 5, background: "#7fb0cc", border: "none", borderRadius: 12, padding: "8px 16px", fontWeight: 700, color: "#15171b", cursor: "pointer", flexShrink: 0, fontSize: 13 }}><Icon name="check" size={15} color="#15171b" /> 完了</button>
      </div>

      {/* ペン設定パネル(5段階の太さ + 種類) */}
      {penOpen && mode === "pen" && (
        <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "9px 14px", background: "#2a2a2c", borderBottom: "1px solid #000", flexWrap: "wrap", flexShrink: 0 }}>
          <span style={{ fontSize: 11, color: "#8b93a0", letterSpacing: 1 }}>太さ</span>
          {PEN_WIDTHS.map((w) => (
            <button key={w} onClick={() => setPenWidth(w)} title={`${w}px`} style={{
              width: 38, height: 34, borderRadius: 10, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
              border: "none", background: penWidth === w ? "rgba(120,176,204,0.28)" : "rgba(255,255,255,0.06)",
            }}>
              <span style={{ width: 22, height: w, borderRadius: 6, background: penWidth === w ? "#9cc8e0" : "#c0c4ca", display: "inline-block" }} />
            </button>
          ))}
          <div style={{ width: 1, height: 24, background: "rgba(255,255,255,0.15)" }} />
          <span style={{ fontSize: 11, color: "#8b93a0", letterSpacing: 1 }}>種類</span>
          {[["pen", "ペン"], ["pencil", "鉛筆"], ["marker", "マーカー"]].map(([t, label]) => (
            <button key={t} onClick={() => setPenType(t)} style={{
              padding: "7px 14px", borderRadius: 10, fontSize: 12, fontWeight: 600, cursor: "pointer", border: "none",
              background: penType === t ? "rgba(120,176,204,0.28)" : "rgba(255,255,255,0.06)",
              color: penType === t ? "#9cc8e0" : "#d9dde2",
            }}>{label}</button>
          ))}
        </div>
      )}

      {/* テキスト設定バー(テキストカードが対象のとき表示: フォント / 文字サイズ / 縦書き横書き) */}
      {mode === "move" && textTarget && (
        <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "9px 14px", background: "#2a2a2c", borderBottom: "1px solid #000", flexWrap: "wrap", flexShrink: 0 }}>
          <span style={{ fontSize: 11, color: "#8b93a0", letterSpacing: 1 }}>あ</span>
          {FONT_OPTIONS.map((f) => (
            <button key={f.id} onClick={() => {
              if (inlineEdit && richApi.current && richApi.current.apply({ font: f.id })) return;
              patchText({ font: f.id });
            }} style={{
              padding: "6px 12px", borderRadius: 10, fontSize: 12, fontWeight: 600, cursor: "pointer", fontFamily: f.css, border: "none",
              background: (textTarget.font || "sans") === f.id ? "rgba(120,176,204,0.28)" : "rgba(255,255,255,0.06)",
              color: (textTarget.font || "sans") === f.id ? "#9cc8e0" : "#d9dde2",
            }}>{f.label}</button>
          ))}
          <div style={{ width: 1, height: 22, background: "rgba(255,255,255,0.15)" }} />
          <span style={{ fontSize: 11, color: "#8b93a0", letterSpacing: 1 }}>サイズ</span>
          <button onClick={() => patchText({ fontSize: Math.max(16, (textTarget.fontSize || 46) - 6) })} style={{
            width: 32, height: 32, borderRadius: 9, border: "none", background: "rgba(255,255,255,0.06)", color: "#d9dde2", fontSize: 16, cursor: "pointer",
          }}>−</button>
          <span style={{ fontSize: 12, color: "#d9dde2", minWidth: 28, textAlign: "center" }}>{textTarget.fontSize || 46}</span>
          <button onClick={() => patchText({ fontSize: Math.min(160, (textTarget.fontSize || 46) + 6) })} style={{
            width: 32, height: 32, borderRadius: 9, border: "none", background: "rgba(255,255,255,0.06)", color: "#d9dde2", fontSize: 16, cursor: "pointer",
          }}>＋</button>
          <div style={{ width: 1, height: 22, background: "rgba(255,255,255,0.15)" }} />
          <button onClick={() => patchText({ vertical: !textTarget.vertical })} style={{
            padding: "7px 14px", borderRadius: 10, fontSize: 12, fontWeight: 600, cursor: "pointer", border: "none",
            background: textTarget.vertical ? "rgba(120,176,204,0.28)" : "rgba(255,255,255,0.06)",
            color: textTarget.vertical ? "#9cc8e0" : "#d9dde2",
          }}>{textTarget.vertical ? "縦書き" : "横書き"}</button>
        </div>
      )}

      <div ref={scrollBox}
        onPointerDown={vpDown} onPointerMove={vpMove} onPointerUp={vpUp} onPointerCancel={vpUp}
        style={{ flex: 1, position: "relative", overflow: "hidden", touchAction: "none" }}>
        <div style={{
          position: "absolute", left: "50%", top: "50%",
          transform: `translate(-50%, -50%) translate(${eview.x}px, ${eview.y}px) scale(${eview.zoom})`,
          transformOrigin: "center center", padding: 26,
          transition: eview.anim ? "transform 0.2s cubic-bezier(0.22,0.61,0.36,1)" : "none", willChange: "transform",
        }}>
        <div ref={stageBox}
          onPointerDown={down} onPointerMove={move} onPointerUp={up} onPointerCancel={up}
          style={{ width: dispW, height: dispH, position: "relative", boxShadow: "0 14px 40px rgba(60,68,78,0.35)", borderRadius: 8, touchAction: "none", cursor: (mode === "pen" || mode === "select") ? "crosshair" : (mode === "eraser" ? "cell" : "default") }}>
          <CardStage
            card={card}
            subCards={inlineEdit ? kids.filter((k) => k.id !== inlineEdit.id) : kids}
            w={dispW} h={dispH}
          />
          {/* 描画中だけ使う高速キャンバス(確定すると上のCardStageに反映) */}
          <canvas ref={liveCanvas} width={Math.round(dispW)} height={Math.round(dispH)}
            style={{ position: "absolute", inset: 0, width: dispW, height: dispH, pointerEvents: "none", zIndex: 3 }} />

          {/* 子カード間の接続矢印 */}
          <svg width={dispW} height={dispH} viewBox={`0 0 ${STAGE_W} ${STAGE_H}`} preserveAspectRatio="none"
            style={{ position: "absolute", inset: 0, pointerEvents: "none" }}>
            <defs>
              <marker id="charrow" markerWidth="7" markerHeight="7" refX="5" refY="3.5" orient="auto">
                <polygon points="0 0, 7 3.5, 0 7" fill={ACCENT_DEEP} />
              </marker>
            </defs>
            {kids.map((ch) => {
              if (!ch.next) return null;
              const t = kids.find((k) => k.id === ch.next);
              if (!t) return null;
              const x1 = ch.x + ch.w, y1 = ch.y + ch.h / 2, x2 = t.x - 6, y2 = t.y + t.h / 2;
              const mx = (x1 + x2) / 2;
              return <path key={"a" + ch.id} d={`M ${x1} ${y1} C ${mx} ${y1}, ${mx} ${y2}, ${x2} ${y2}`}
                stroke={ACCENT_DEEP} strokeWidth="5" fill="none" markerEnd="url(#charrow)" opacity="0.85"
                strokeDasharray="0.5 13" strokeLinecap="round" />;
            })}
            {connectLine && selectedCh && (
              <line x1={selectedCh.x + selectedCh.w} y1={selectedCh.y + selectedCh.h / 2}
                x2={connectLine.x} y2={connectLine.y}
                stroke={ACCENT_DEEP} strokeWidth="5" strokeDasharray="10 8" markerEnd="url(#charrow)" />
            )}
          </svg>

          {/* 範囲選択(フリーハンドの軌跡) */}
          {lassoPath && lassoPath.length > 1 && (
            <svg width={dispW} height={dispH} viewBox={`0 0 ${STAGE_W} ${STAGE_H}`} preserveAspectRatio="none"
              style={{ position: "absolute", inset: 0, pointerEvents: "none", zIndex: 5 }}>
              <polygon points={lassoPath.map((p) => p.join(",")).join(" ")}
                fill="rgba(167,201,219,0.18)" stroke={ACCENT_DEEP} strokeWidth="2.5"
                strokeDasharray="8 6" strokeLinejoin="round" />
            </svg>
          )}
          {/* 選択済みストロークの枠 + 操作ハンドル */}
          {mode === "select" && selBBox && selStrokeIds.length > 0 && (
            <>
              <div style={{
                position: "absolute", left: selBBox.minX * s - 6, top: selBBox.minY * s - 6,
                width: (selBBox.maxX - selBBox.minX) * s + 12, height: (selBBox.maxY - selBBox.minY) * s + 12,
                border: `1.5px solid ${ACCENT_DEEP}`, borderRadius: 6, pointerEvents: "none", zIndex: 5,
                background: "rgba(167,201,219,0.08)",
              }} />
              {/* 削除 */}
              <button onPointerDown={(e) => e.stopPropagation()}
                onClick={() => { patchCard(card.id, { strokes: card.strokes.filter((st) => !selStrokeIds.includes(st.id)) }); setSelStrokeIds([]); }}
                style={{
                  position: "absolute", left: selBBox.minX * s - 6 - 11, top: selBBox.minY * s - 6 - 11,
                  width: 24, height: 24, borderRadius: 12, border: "none", background: "#d04030", color: "#fff",
                  fontSize: 12, cursor: "pointer", zIndex: 7, boxShadow: "0 2px 6px rgba(60,68,78,0.4)",
                }}><UIcon name="trash" size={15} color="#fff" /></button>
              {/* 拡大縮小(右下) */}
              <div
                onPointerDown={(e) => {
                  e.stopPropagation();
                  strokeResize.current = { ax: selBBox.minX, ay: selBBox.minY, bx: selBBox.maxX, by: selBBox.maxY, lastK: 1 };
                  try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {}
                }}
                onPointerMove={(e) => { if (strokeResize.current) move(e); }}
                onPointerUp={() => { strokeResize.current = null; }}
                style={{
                  position: "absolute", left: selBBox.maxX * s + 6 - 11, top: selBBox.maxY * s + 6 - 11,
                  width: 22, height: 22, borderRadius: 11, background: ACCENT_DEEP, border: "2px solid #fff",
                  cursor: "nwse-resize", touchAction: "none", zIndex: 7, boxShadow: "0 2px 6px rgba(60,68,78,0.4)",
                }} />
            </>
          )}

          {/* 選択中の子カード: 枠 + ハンドル */}
          {selectedCh && mode === "move" && (
            <>
              <div style={{
                position: "absolute", left: selectedCh.x * s, top: selectedCh.y * s,
                width: selectedCh.w * s, height: selectedCh.h * s,
                border: `1.5px dashed ${ACCENT_DEEP}`, borderRadius: 8, pointerEvents: "none", zIndex: 4,
              }} />
              {/* 接続(右辺中央の○) */}
              <div
                onPointerDown={connDown(selectedCh)} onPointerMove={connMove()} onPointerUp={connUp()} onPointerCancel={connUp()}
                style={{
                  position: "absolute", left: (selectedCh.x + selectedCh.w) * s - 9, top: (selectedCh.y + selectedCh.h / 2) * s - 11,
                  width: 22, height: 22, borderRadius: 11, background: SURFACE, border: `2px solid ${ACCENT_DEEP}`,
                  display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, color: ACCENT_DEEP,
                  cursor: "crosshair", zIndex: 6, touchAction: "none", boxShadow: "0 2px 6px rgba(60,68,78,0.3)",
                }}><UIcon name="link" size={13} color="#fff" /></div>
              {/* 接続解除(接続がある場合) */}
              {selectedCh.next && (
                <button onPointerDown={(e) => e.stopPropagation()}
                  onClick={() => patchCard(selectedCh.id, { next: null })}
                  style={{
                    position: "absolute", left: (selectedCh.x + selectedCh.w) * s + 16, top: (selectedCh.y + selectedCh.h / 2) * s - 11,
                    height: 22, borderRadius: 11, border: `1px solid ${BORDER}`, background: SURFACE, color: SUBTLE,
                    fontSize: 9, padding: "0 8px", cursor: "pointer", zIndex: 6,
                  }}>解除</button>
              )}
              {/* リサイズ(右下角・ピン留め中は非表示) */}
              {!selectedCh.pinned && (
                <div
                  onPointerDown={(e) => { e.stopPropagation(); resizeChild.current = { id: selectedCh.id }; e.currentTarget.setPointerCapture(e.pointerId); }}
                  onPointerMove={(e) => { if (resizeChild.current) move(e); }}
                  onPointerUp={() => { resizeChild.current = null; }}
                  style={{
                    position: "absolute", left: (selectedCh.x + selectedCh.w) * s - 10, top: (selectedCh.y + selectedCh.h) * s - 10,
                    width: 20, height: 20, borderRadius: 10, background: ACCENT_DEEP, border: "2px solid #fff",
                    cursor: "nwse-resize", zIndex: 6, touchAction: "none", boxShadow: "0 2px 6px rgba(60,68,78,0.35)",
                  }} />
              )}
              {selectedCh.pinned && (
                <div style={{
                  position: "absolute", left: selectedCh.x * s - 4, top: selectedCh.y * s - 10,
                  fontSize: 15, zIndex: 6, pointerEvents: "none",
                }}><UIcon name="pin" size={15} color={PINK} /></div>
              )}
            </>
          )}

          {/* 子テキストのインライン編集 */}
          {inlineEdit && (() => {
            const ch = kids.find((k) => k.id === inlineEdit.id);
            if (!ch) return null;
            return (
              <div onPointerDown={(e) => e.stopPropagation()}
                style={{ position: "absolute", left: ch.x * s, top: ch.y * s, zIndex: 7 }}>
                <RichEditable
                  initialRuns={ch.runs} initialText={ch.text}
                  baseColor={ch.textColor || INK} baseFont={ch.font}
                  fontSize={Math.max((ch.fontSize || 46) * s, 14)}
                  registerApply={(api) => { richApi.current = api; }}
                  style={{
                    width: Math.max(ch.w * s, 150), minHeight: Math.max(ch.h * s, 48), fontWeight: 700, lineHeight: 1.3,
                    background: "rgba(255,255,255,0.92)", border: `2px dashed ${ACCENT_DEEP}`, borderRadius: 8, padding: 5,
                  }} />
                <div style={{ display: "flex", gap: 6, marginTop: 4, flexWrap: "wrap" }}>
                  <button onClick={() => {
                    const runs = richApi.current ? richApi.current.getRuns() : null;
                    const plain = runsToText(runs).replace(/\\s+$/, "");
                    if (plain === "") { removeDeep(inlineEdit.id); }
                    else {
                      const simple = runs && runs.length === 1 && !runs[0].color && !runs[0].font;
                      patchCard(inlineEdit.id, simple ? { text: plain, runs: null } : { text: plain, runs });
                    }
                    setInlineEdit(null);
                  }} style={{ background: ACCENT_DEEP, color: "#fff", border: "none", borderRadius: 12, padding: "5px 14px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>確定</button>
                  <button onClick={() => { removeDeep(inlineEdit.id); setInlineEdit(null); setSelected(null); }}
                    style={{ background: "#d04030", color: "#fff", border: "none", borderRadius: 12, padding: "5px 14px", fontSize: 13, cursor: "pointer" }}>削除</button>
                  <button onClick={() => setInlineEdit(null)} style={{ background: SURFACE, color: INK, border: `1px solid ${BORDER}`, borderRadius: 12, padding: "5px 14px", fontSize: 13, cursor: "pointer" }}>取消</button>
                  <span style={{ fontSize: 10, color: SUBTLE, alignSelf: "center" }}>文字を選んで上のフォント・色を押すと部分変更できます</span>
                </div>
              </div>
            );
          })()}

          {/* このカード自身の文字編集 */}
          {selfEdit && (
            <div onPointerDown={(e) => e.stopPropagation()}
              style={{ position: "absolute", left: "8%", top: "10%", width: "84%", zIndex: 7 }}>
              <textarea autoFocus value={selfEdit.value}
                onChange={(e) => setSelfEdit({ value: e.target.value })}
                placeholder="このカードの文字"
                style={{
                  width: "100%", boxSizing: "border-box", minHeight: 120,
                  fontSize: Math.max((card.fontSize || 46) * s, 15), fontWeight: 700, color: card.textColor || INK, lineHeight: 1.3,
                  background: "rgba(255,255,255,0.92)", border: `2px dashed ${ACCENT_DEEP}`, borderRadius: 10,
                  padding: 8, resize: "vertical", outline: "none", fontFamily: "inherit",
                }} />
              <div style={{ display: "flex", gap: 6, marginTop: 4 }}>
                <button onClick={commitSelf} style={{ background: ACCENT_DEEP, color: "#fff", border: "none", borderRadius: 12, padding: "5px 14px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>確定</button>
                <button onClick={() => setSelfEdit(null)} style={{ background: SURFACE, color: INK, border: `1px solid ${BORDER}`, borderRadius: 12, padding: "5px 14px", fontSize: 13, cursor: "pointer" }}>取消</button>
              </div>
            </div>
          )}
        </div>
        </div>
      </div>

      {/* 子カードの長押しメニュー */}
      {childMenu && (() => {
        const ch = kids.find((k) => k.id === childMenu.id);
        if (!ch) return null;
        return (
          <div style={{
            position: "fixed", left: Math.min(childMenu.vx, window.innerWidth - 170), top: Math.min(childMenu.vy, window.innerHeight - 160),
            background: SURFACE, borderRadius: 14, boxShadow: "0 8px 28px rgba(40,44,50,0.35)", zIndex: 150 + depth,
            overflow: "hidden", width: 160,
          }}>
            {[
              ["copy", "複製", () => {
                addCards([{ ...ch, id: uid(), x: ch.x + 30, y: ch.y + 30, next: null,
                  strokes: ch.strokes.map((st) => ({ ...st, id: uid(), points: st.points.map((p) => [...p]) })) }]);
              }],
              ["pin", ch.pinned ? "ピン解除" : "ピン留め", () => patchCard(ch.id, { pinned: !ch.pinned })],
              ["detach", "外に出す", () => { detachChild(ch.id); setSelected(null); showToast("キャンバスに独立カードとして置きました"); }],
              ["trash", "削除", () => { removeDeep(ch.id); setSelected(null); }],
            ].map(([icon, label, fn]) => (
              <button key={label} onClick={() => { fn(); setChildMenu(null); }} style={{
                display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "12px 14px", border: "none", background: "none",
                textAlign: "left", fontSize: 14, cursor: "pointer", borderBottom: `1px solid ${BORDER}`, color: icon === "trash" ? "#e58a94" : INK,
              }}><UIcon name={icon} size={17} color={icon === "trash" ? "#e58a94" : SUBTLE} /> {label}</button>
            ))}
          </div>
        );
      })()}

      <input ref={imgInput} type="file" accept="image/*" style={{ display: "none" }}
        onChange={(e) => { if (e.target.files[0]) addChildImage(e.target.files[0]); e.target.value = ""; }} />
    </div>
  );
}

/* ============================================================
   スワイプ閲覧(まとめカードを開く)
   ============================================================ */
function SwipeViewer({ chain, allCards, onClose, onEdit, onDuplicate, onDelete }) {
  const [idx, setIdx] = useState(0);
  const startX = useRef(null);
  const [vp, setVp] = useState({ w: window.innerWidth, h: window.innerHeight });
  const [paMenu, setPaMenu] = useState(null); // ページアシストの長押しメニュー {id, i}
  const lp = useRef(null);
  useEffect(() => {
    const f = () => setVp({ w: window.innerWidth, h: window.innerHeight });
    window.addEventListener("resize", f);
    return () => window.removeEventListener("resize", f);
  }, []);
  const s = Math.min((vp.w - 32) / STAGE_W, (vp.h - 220) / STAGE_H);
  const safeIdx = Math.min(idx, chain.length - 1);
  const card = chain[safeIdx];
  const thumbS = 64 / STAGE_W; // サムネイルの縮尺
  if (!card) return null;

  return (
    <div style={{ position: "fixed", inset: 0, background: "#1c1c1c", zIndex: 90, display: "flex", flexDirection: "column" }}
      onPointerDown={(e) => (startX.current = e.clientX)}
      onPointerUp={(e) => {
        if (startX.current === null) return;
        const dx = e.clientX - startX.current;
        if (dx < -50 && idx < chain.length - 1) setIdx(idx + 1);
        if (dx > 50 && idx > 0) setIdx(idx - 1);
        startX.current = null;
      }}>
      <div style={{ height: 56, display: "flex", alignItems: "center", padding: "0 14px", gap: 10, color: "#d9dde2" }}>
        <button onClick={onClose} style={{ background: "none", border: "none", color: "#d9dde2", width: 40, height: 40, fontSize: 22, cursor: "pointer" }}>‹</button>
        <div style={{ flex: 1, textAlign: "center", fontWeight: 700, letterSpacing: 1, fontSize: 13 }}>{safeIdx + 1} / {chain.length}</div>
        <button onClick={() => onEdit(card.id)} style={{ background: "#7fb0cc", color: "#15171b", border: "none", borderRadius: 14, padding: "8px 18px", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>編集</button>
      </div>
      <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <button onClick={() => setIdx(Math.max(0, idx - 1))} disabled={idx === 0}
          style={{ background: "none", border: "none", color: idx === 0 ? "#444" : "#d9dde2", fontSize: 34, cursor: "pointer" }}>‹</button>
        <div style={{ boxShadow: "0 16px 50px rgba(0,0,0,0.5)", borderRadius: 14, overflow: "hidden", border: "1px solid #333" }}>
          <CardStage card={card} subCards={childrenOf(allCards, card.id)} w={STAGE_W * s} h={STAGE_H * s} />
        </div>
        <button onClick={() => setIdx(Math.min(chain.length - 1, idx + 1))} disabled={idx === chain.length - 1}
          style={{ background: "none", border: "none", color: idx === chain.length - 1 ? "#444" : "#d9dde2", fontSize: 34, cursor: "pointer" }}>›</button>
      </div>

      {/* ページアシスト(Procreate風) */}
      <div style={{ padding: "0 14px 18px" }}>
        <div style={{
          background: "#2a2a2c", borderRadius: 22, padding: "12px 16px 14px",
          boxShadow: "0 8px 30px rgba(0,0,0,0.5)",
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            <span style={{ fontSize: 13, color: "#d9dde2", fontWeight: 600 }}>ページアシスト</span>
            <span style={{ fontSize: 12, color: "#8b93a0" }}>{chain.length}枚</span>
          </div>
          <div style={{ display: "flex", gap: 10, overflowX: "auto", paddingBottom: 4 }}>
            {chain.map((c, i) => (
              <div key={c.id} style={{ position: "relative", flexShrink: 0 }}
                onPointerDown={(e) => {
                  const id = c.id;
                  lp.current = setTimeout(() => { feedback(); setPaMenu({ id, i }); }, 480);
                }}
                onPointerUp={() => { clearTimeout(lp.current); }}
                onPointerLeave={() => { clearTimeout(lp.current); }}
              >
                <div onClick={() => setIdx(i)} style={{
                  width: 64, height: 48, borderRadius: 8, overflow: "hidden", cursor: "pointer",
                  border: i === safeIdx ? "2.5px solid #7fb0cc" : "2px solid #444",
                  background: "#fff",
                }}>
                  <CardStage card={c} subCards={childrenOf(allCards, c.id)} w={STAGE_W * thumbS} h={STAGE_H * thumbS} />
                </div>
                <span style={{ position: "absolute", bottom: 2, right: 4, fontSize: 9, color: "#fff", textShadow: "0 1px 2px #000", fontWeight: 700 }}>{i + 1}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ページアシストの長押しメニュー */}
      {paMenu && (
        <div onClick={() => setPaMenu(null)} style={{ position: "fixed", inset: 0, zIndex: 95, background: "rgba(0,0,0,0.4)", display: "flex", alignItems: "flex-end", justifyContent: "center", paddingBottom: 120 }}>
          <div onClick={(e) => e.stopPropagation()} style={{ background: SURFACE, borderRadius: 16, overflow: "hidden", width: 220, boxShadow: SHADOW_POP, border: `1px solid ${BORDER}` }}>
            <div style={{ padding: "10px 14px", fontSize: 11, color: SUBTLE, borderBottom: `1px solid ${BORDER}` }}>{paMenu.i + 1}枚目のカード</div>
            <button onClick={() => { onDuplicate && onDuplicate(paMenu.id); setPaMenu(null); }} style={{
              display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "13px 16px", border: "none", background: "none",
              textAlign: "left", fontSize: 14, cursor: "pointer", borderBottom: `1px solid ${BORDER}`, color: INK,
            }}><UIcon name="copy" size={17} color={SUBTLE} /> 複製</button>
            <button onClick={() => {
              if (chain.length <= 1) { onClose(); }
              onDelete && onDelete(paMenu.id);
              setPaMenu(null);
              setIdx((v) => Math.max(0, Math.min(v, chain.length - 2)));
            }} style={{
              display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "13px 16px", border: "none", background: "none",
              textAlign: "left", fontSize: 14, cursor: "pointer", color: "#e58a94",
            }}><UIcon name="trash" size={17} color="#e58a94" /> 削除</button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ============================================================
   無限キャンバス画面 — 暗いグレー地(格子なし)
   レイアウト: 下中央ツールドック / 右端に資料箱・共有 /
   上中央ゴミ箱 / 接続は右辺中央の○ハンドル
   ============================================================ */
function CanvasScreen({ note, group, groups, onUpdateCards, onBack, materialBox, setMaterialBox, onSendCard, tut = null, onTutAdvance = () => {}, onTutEnd = () => {} }) {
  const cards = note.cards;
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [scale, setScale] = useState(1); // キャンバスのズーム倍率
  const [zoomAnim, setZoomAnim] = useState(false); // ボタン操作時だけ滑らかに
  const bgPointers = useRef(new Map());  // 背景に触れている指
  const bgPinch = useRef(null);          // {dist, scale, cx, cy, panx, pany}
  const zoomAnimTimer = useRef(null);
  const [editStack, setEditStack] = useState([]);   // 開いているカードの階層
  const [viewerHead, setViewerHead] = useState(null);
  const [menu, setMenu] = useState(null);
  const [connectLine, setConnectLine] = useState(null);
  const [trashHot, setTrashHot] = useState(false);
  const [boxHot, setBoxHot] = useState(false);
  const [shareHot, setShareHot] = useState(false);
  const [hoverTarget, setHoverTarget] = useState(null); // ドラッグ中に重なっているカード
  const [boxOpen, setBoxOpen] = useState(false);
  const [boxDrop, setBoxDrop] = useState(null);
  const [shareDrop, setShareDrop] = useState(null);
  const [palette, setPalette] = useState(false);
  const [toast, setToast] = useState(null);
  const [promptD, setPromptD] = useState(null);
  const [confirmD, setConfirmD] = useState(null);
  const toastTimer = useRef(null);
  const viewport = useRef(null);
  const panRef = useRef(null);
  const dragRef = useRef(null);
  const resizeRef = useRef(null);
  const connectRef = useRef(null);
  const tapRef = useRef({ t: 0, id: null });
  const tapTimer = useRef(null);
  const longPress = useRef(null);
  const fileInput = useRef(null);
  const pdfInput = useRef(null);
  const camInput = useRef(null);
  const trashRef = useRef(null);
  const boxBtnRef = useRef(null);
  const shareBtnRef = useRef(null);

  const showToast = (msg) => {
    setToast(msg);
    clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(null), 2400);
  };

  /* ---- 操作履歴(巻き戻し / やり直し) ---- */
  const undoStack = useRef([]);
  const redoStack = useRef([]);
  const lastPush = useRef(0);
  const setCards = (fn) => {
    const next = typeof fn === "function" ? fn(cards) : fn;
    if (next === cards) return;
    // ドラッグや手書きの連続更新は1つの履歴にまとめる(400ms以内は追加しない)
    const now = Date.now();
    if (now - lastPush.current > 400) {
      undoStack.current.push(cards);
      if (undoStack.current.length > 60) undoStack.current.shift();
    }
    lastPush.current = now;
    redoStack.current = [];
    onUpdateCards(next);
  };
  const undo = () => {
    if (!undoStack.current.length) { showToast("これ以上戻せません"); return; }
    const prev = undoStack.current.pop();
    redoStack.current.push(cards);
    lastPush.current = 0;
    onUpdateCards(prev);
    showToast("ひとつ前に戻しました");
  };
  const redo = () => {
    if (!redoStack.current.length) { showToast("やり直せる操作がありません"); return; }
    const next = redoStack.current.pop();
    undoStack.current.push(cards);
    lastPush.current = 0;
    onUpdateCards(next);
    showToast("やり直しました");
  };

  /* ---- 2本指タップ=巻き戻し / 3本指タップ=やり直し ---- */
  const multiRef = useRef({ count: 0, max: 0, t: 0 });
  const mtDown = () => {
    const m = multiRef.current;
    m.count++;
    if (m.count === 1) { m.t = Date.now(); m.max = 1; }
    m.max = Math.max(m.max, m.count);
  };
  const mtUp = () => {
    const m = multiRef.current;
    m.count = Math.max(0, m.count - 1);
    if (m.count === 0) {
      const quick = Date.now() - m.t < 420;
      const pinched = bgPinch.current || multiRef.current.pinched;
      const blocked = editStack.length > 0 || viewerHead || boxOpen || boxDrop || shareDrop || menu || pinched;
      if (quick && !blocked) {
        if (m.max === 2) undo();
        else if (m.max === 3) redo();
      }
      multiRef.current = { count: 0, max: 0, t: 0, pinched: false };
    }
  };
  const patchCard = (id, patch) => setCards((cs) => cs.map((c) => (c.id === id ? { ...c, ...patch } : c)));
  const addCards = (arr) => setCards((cs) => [...cs, ...arr]);
  // カードとその子をまとめて削除(参照も掃除)
  const removeDeep = (id) => {
    setCards((cs) => {
      const dead = new Set([id, ...cs.filter((c) => c.parentId === id).map((c) => c.id)]);
      return cs.filter((c) => !dead.has(c.id)).map((c) => (dead.has(c.next) ? { ...c, next: null } : c));
    });
  };
  // 子カードをキャンバスへ独立させる
  const detachChild = (childId) => {
    setCards((cs) => {
      const ch = cs.find((c) => c.id === childId);
      if (!ch || !ch.parentId) return cs;
      const parent = cs.find((c) => c.id === ch.parentId);
      const scaleW = parent ? parent.w / STAGE_W : 0.3;
      const scaleH = parent ? parent.h / STAGE_H : 0.3;
      const nw = Math.max(110, ch.w * scaleW), nh = Math.max(80, ch.h * scaleH);
      const fontBoost = typeof ch.text === "string" ? STAGE_W / Math.max(ch.w, 1) : 1;
      return cs.map((c) => {
        if (c.id === childId) {
          return {
            ...c, parentId: null,
            x: (parent ? parent.x + parent.w : 100) + 26,
            y: (parent ? parent.y : 100) + 10,
            w: nw, h: nh, next: null,
            fontSize: typeof c.text === "string" ? Math.round((c.fontSize || 46) * fontBoost) : c.fontSize,
            color: c.type === "text" && (!c.color || c.color === "transparent") ? "transparent" : c.color,
            textColor: typeof c.text === "string" && isDarkColor(c.textColor || "#3f4750") && (!c.color || c.color === "transparent")
              ? "#f0f2f4" : c.textColor,
          };
        }
        return c.next === childId ? { ...c, next: null } : c;
      });
    });
  };

  const topLevel = cards.filter((c) => !c.parentId);
  const incoming = buildIncoming(topLevel);
  const hiddenIds = new Set();
  topLevel.forEach((c) => {
    if (c.collapsed && !incoming[c.id] && c.next) {
      chainFrom(topLevel, c.id).slice(1).forEach((m) => hiddenIds.add(m.id));
    }
  });
  const visible = topLevel.filter((c) => !hiddenIds.has(c.id));

  const toCanvas = (e) => {
    const r = viewport.current.getBoundingClientRect();
    return [(e.clientX - r.left - pan.x) / scale, (e.clientY - r.top - pan.y) / scale];
  };
  // ズーム(focalを中心に拡大縮小。focalはビューポート内のpx座標)
  const zoomAt = (nextScale, fx, fy) => {
    const ns = Math.min(3, Math.max(0.3, nextScale));
    setPan((p) => ({
      x: fx - (fx - p.x) * (ns / scale),
      y: fy - (fy - p.y) * (ns / scale),
    }));
    setScale(ns);
  };
  const zoomButton = (factor) => {
    const r = viewport.current ? viewport.current.getBoundingClientRect() : { width: 800, height: 600 };
    setZoomAnim(true);
    clearTimeout(zoomAnimTimer.current);
    zoomAnimTimer.current = setTimeout(() => setZoomAnim(false), 260);
    zoomAt(scale * factor, r.width / 2, r.height / 2);
  };
  const overEl = (e, ref) => {
    if (!ref.current) return false;
    const r = ref.current.getBoundingClientRect();
    return e.clientX >= r.left - 10 && e.clientX <= r.right + 10 && e.clientY >= r.top - 10 && e.clientY <= r.bottom + 10;
  };
  const cloneBundleOf = (id, pos) => cloneBundle(collectBundle(cards, id), pos);

  // 連結チェーン全体(親+子)を丸ごと複製。矢印のつながりも維持
  const duplicateChain = (headId) => {
    const chain = chainFrom(topLevel, headId);
    const idMap = {};
    const all = [];
    chain.forEach((c) => {
      const bundle = collectBundle(cards, c.id);
      const m = {};
      bundle.forEach((b) => { m[b.id] = uid(); });
      idMap[c.id] = m[c.id];
      bundle.forEach((b, i) => {
        all.push({
          ...b, id: m[b.id],
          parentId: b.parentId ? (m[b.parentId] || null) : null,
          x: i === 0 ? b.x + 36 : b.x, y: i === 0 ? b.y + 36 : b.y,
          next: null, collapsed: false,
          strokes: b.strokes.map((s) => ({ ...s, id: uid(), points: s.points.map((p) => [...p]) })),
          tags: [...b.tags],
        });
      });
    });
    // 矢印の再リンク
    chain.forEach((c) => {
      if (c.next && idMap[c.next]) {
        const nc = all.find((a) => a.id === idMap[c.id]);
        if (nc) nc.next = idMap[c.next];
      }
    });
    addCards(all);
  };

  // チェーン全体を削除
  const deleteChain = (headId) => {
    chainFrom(topLevel, headId).forEach((c) => removeDeep(c.id));
  };

  // チェーンを矢印順にきれいに整列(横一列、収まらなければ折り返して格子に)
  const alignChain = (headId) => {
    const chain = chainFrom(topLevel, headId);
    if (chain.length < 2) return;
    const gap = 28;
    const maxW = Math.max(...chain.map((c) => c.w));
    const maxH = Math.max(...chain.map((c) => c.h));
    const viewW = viewport.current ? viewport.current.getBoundingClientRect().width : 900;
    const perRow = Math.max(1, Math.floor((viewW - 80) / (maxW + gap)));
    const x0 = chain[0].x, y0 = chain[0].y;
    setCards((cs) => cs.map((c) => {
      const idx = chain.findIndex((x) => x.id === c.id);
      if (idx < 0) return c;
      const row = Math.floor(idx / perRow), col = idx % perRow;
      return { ...c, x: x0 + col * (maxW + gap), y: y0 + row * (maxH + gap), pinned: false };
    }));
    showToast("整列しました");
  };

  /* ---- 背景パン + ピンチズーム ---- */
  const bgDist = () => {
    const ps = [...bgPointers.current.values()];
    return Math.hypot(ps[0].x - ps[1].x, ps[0].y - ps[1].y);
  };
  const bgCenter = () => {
    const ps = [...bgPointers.current.values()];
    const r = viewport.current.getBoundingClientRect();
    return { x: (ps[0].x + ps[1].x) / 2 - r.left, y: (ps[0].y + ps[1].y) / 2 - r.top };
  };
  const bgDown = (e) => {
    bgPointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    if (bgPointers.current.size === 2) {
      panRef.current = null; // 1本指パンを中断
      const c = bgCenter();
      setZoomAnim(false);
      bgPinch.current = { dist: bgDist(), scale, cx: c.x, cy: c.y, panx: pan.x, pany: pan.y, lastc: c };
      try { e.currentTarget.setPointerCapture(e.pointerId); } catch (err) {}
      return;
    }
    if (bgPointers.current.size > 2) return;
    panRef.current = { sx: e.clientX, sy: e.clientY, px: pan.x, py: pan.y };
    e.currentTarget.setPointerCapture(e.pointerId);
    setMenu(null);
    setPalette(false);
  };
  const bgMove = (e) => {
    if (bgPointers.current.has(e.pointerId)) bgPointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    if (bgPinch.current && bgPointers.current.size >= 2) {
      const d = bgDist();
      const c = bgCenter();
      const bp = bgPinch.current;
      if (bp.dist > 0) {
        const ns = Math.min(3, Math.max(0.3, bp.scale * (d / bp.dist)));
        // 2本指の中心を基準に拡大しつつ、中心の移動ぶんパンも反映
        setPan({
          x: c.x - (bp.cx - bp.panx) * (ns / bp.scale) + (c.x - bp.cx),
          y: c.y - (bp.cy - bp.pany) * (ns / bp.scale) + (c.y - bp.cy),
        });
        setScale(ns);
        multiRef.current.pinched = true;
      }
      return;
    }
    if (panRef.current) setPan({ x: panRef.current.px + e.clientX - panRef.current.sx, y: panRef.current.py + e.clientY - panRef.current.sy });
  };
  const bgUp = (e) => {
    bgPointers.current.delete(e.pointerId);
    if (bgPinch.current && bgPointers.current.size < 2) bgPinch.current = null;
    if (bgPointers.current.size === 0) panRef.current = null;
  };

  /* ---- カード操作 ---- */
  const cardDown = (card) => (e) => {
    e.stopPropagation();
    setMenu(null);
    setPalette(false);
    const [cx, cy] = toCanvas(e);
    dragRef.current = { id: card.id, dx: cx - card.x, dy: cy - card.y, moved: false, sx: e.clientX, sy: e.clientY };
    e.currentTarget.setPointerCapture(e.pointerId);
    longPress.current = setTimeout(() => {
      if (dragRef.current && !dragRef.current.moved) {
        const r = viewport.current.getBoundingClientRect();
        setMenu({ cardId: card.id, vx: e.clientX - r.left, vy: e.clientY - r.top });
        dragRef.current = null;
      }
    }, 550);
  };
  const cardMove = (card) => (e) => {
    const d = dragRef.current;
    if (!d || d.id !== card.id) return;
    if (!d.moved && Math.hypot(e.clientX - d.sx, e.clientY - d.sy) < 7) return;
    d.moved = true;
    clearTimeout(longPress.current);
    if (card.pinned) return;
    const [cx, cy] = toCanvas(e);
    patchCard(card.id, { x: cx - d.dx, y: cy - d.dy });
    setTrashHot(overEl(e, trashRef));
    setBoxHot(overEl(e, boxBtnRef));
    setShareHot(overEl(e, shareBtnRef));
    // 別のカードの上に重なっているか(重ねると子カードにできる)
    const tgt = cardAtPoint(cx, cy, card.id);
    setHoverTarget(tgt ? tgt.id : null);
  };
  // 指定座標にある別のトップレベルカードを探す(自分・自分の子孫は除く)
  const cardAtPoint = (cx, cy, selfId) => {
    return [...visible].reverse().find((c) =>
      c.id !== selfId && c.type !== "pdf" && c.type !== "web" &&
      cx >= c.x && cx <= c.x + c.w && cy >= c.y && cy <= c.y + c.h);
  };
  // カードを別カードの子(テキスト/画像)として取り込む
  const nestInto = (childCard, parentCard) => {
    // 親の800x600座標系に変換して配置(中央寄せ)
    const childW = childCard.type === "image" ? 320 : 340;
    const childH = childCard.type === "image" ? 220 : 140;
    setCards((cs) => {
      // childCardとその子(あれば)を巻き込むと複雑なので、childは単独カード前提でparentIdを付ける
      return cs.map((c) => {
        if (c.id === childCard.id) {
          return {
            ...c, parentId: parentCard.id, next: null, collapsed: false, pinned: false,
            x: STAGE_W / 2 - childW / 2, y: STAGE_H / 2 - childH / 2, w: childW, h: childH,
            // 暗い背景キャンバスから子に入るので、テキスト色が暗いと見えにくい→補正
            textColor: typeof c.text === "string" && isDarkColor(c.textColor || "#3f4750") ? "#3f4750" : c.textColor,
          };
        }
        // childを指していた接続を解除
        return c.next === childCard.id ? { ...c, next: null } : c;
      });
    });
    showToast(`「${parentCard.type === "text" && parentCard.text ? parentCard.text.slice(0, 6) : "カード"}」の中に入れました`);
  };
  const cardUp = (card) => (e) => {
    clearTimeout(longPress.current);
    const d = dragRef.current;
    dragRef.current = null;
    if (multiRef.current.max >= 2) { setTrashHot(false); setBoxHot(false); setShareHot(false); setHoverTarget(null); return; }
    setTrashHot(false); setBoxHot(false); setShareHot(false);
    const hov = hoverTarget;
    setHoverTarget(null);
    if (!d) return;
    if (d.moved) {
      if (overEl(e, trashRef) && !card.pinned) removeDeep(card.id);
      else if (overEl(e, boxBtnRef)) setBoxDrop(card.id);
      else if (overEl(e, shareBtnRef)) setShareDrop(card.id);
      else if (hov) {
        // 別カードの上で離した → 子カードとして取り込む
        const parent = cards.find((c) => c.id === hov);
        if (parent && parent.id !== card.id) nestInto(card, parent);
      }
      return;
    }
    // タップ判定(1回=閲覧 / 2回=編集 / 3回=まとめ・展開)
    const now = Date.now();
    const isHead = !incoming[card.id] && card.next;
    if (tapRef.current.id === card.id && now - tapRef.current.t < 360) {
      tapRef.current = { id: card.id, t: now, count: (tapRef.current.count || 1) + 1 };
    } else {
      tapRef.current = { id: card.id, t: now, count: 1 };
    }
    const myTap = tapRef.current.count;
    clearTimeout(tapTimer.current);
    tapTimer.current = setTimeout(() => {
      if (tapRef.current.id !== card.id) return;
      const cnt = tapRef.current.count;
      tapRef.current = { t: 0, id: null, count: 0 };
      if (cnt >= 3) {
        // 3回タップ: 連結チェーンのまとめ/展開
        if (isHead) patchCard(card.id, { collapsed: !card.collapsed });
        else showToast("まとめるには、矢印でつないだ先頭のカードを3回タップしてね");
      } else if (cnt === 2) {
        setEditStack([card.id]); // 編集
      } else {
        if (isHead && card.collapsed) setViewerHead(card.id); // 閲覧
      }
    }, 360);
  };

  /* ---- リサイズ(四隅=全体拡大 / 4辺=枠だけ変更で中身は固定) ---- */
  const resizeDown = (card, k) => (e) => {
    e.stopPropagation();
    resizeRef.current = {
      id: card.id, k, sx: e.clientX, sy: e.clientY,
      w0: card.w, h0: card.h, x0: card.x, y0: card.y,
      cw0: card.cw || card.w, ch0: card.ch || card.h, fs0: card.fontSize || 46,
    };
    e.currentTarget.setPointerCapture(e.pointerId);
  };
  const resizeMove = (card) => (e) => {
    const r = resizeRef.current;
    if (!r || r.id !== card.id) return;
    const dx = (e.clientX - r.sx) / scale;
    const dy = (e.clientY - r.sy) / scale;
    const isCorner = r.k.length === 2; // nw/ne/sw/se
    if (isCorner) {
      // 四隅: カード全体を拡大縮小(中身も一緒に)。縦横比維持
      const signX = r.k.includes("e") ? 1 : -1;
      const ratio = Math.max(0.3, (r.w0 + dx * signX) / r.w0);
      const nw = Math.max(90, Math.round(r.w0 * ratio));
      const nh = Math.max(70, Math.round(r.h0 * ratio));
      const patch = { w: nw, h: nh };
      if (r.k.includes("w")) patch.x = r.x0 + (r.w0 - nw);
      if (r.k.includes("n")) patch.y = r.y0 + (r.h0 - nh);
      if (card.cw) patch.cw = Math.round(r.cw0 * ratio);
      if (card.ch) patch.ch = Math.round(r.ch0 * ratio);
      if (typeof card.text === "string") patch.fontSize = Math.max(10, Math.round(r.fs0 * ratio));
      patchCard(card.id, patch);
    } else {
      // 4辺: 枠だけ変更(中身は固定)。初回に中身サイズをロック
      const patch = { cw: r.cw0, ch: r.ch0 };
      if (r.k === "e") patch.w = Math.max(60, Math.round(r.w0 + dx));
      if (r.k === "w") { const nw = Math.max(60, Math.round(r.w0 - dx)); patch.w = nw; patch.x = r.x0 + (r.w0 - nw); }
      if (r.k === "s") patch.h = Math.max(50, Math.round(r.h0 + dy));
      if (r.k === "n") { const nh = Math.max(50, Math.round(r.h0 - dy)); patch.h = nh; patch.y = r.y0 + (r.h0 - nh); }
      patchCard(card.id, patch);
    }
  };
  const resizeUp = () => { resizeRef.current = null; };
  // カード全体を倍率で拡大縮小(中身も一緒に・中心を維持)
  const scaleCard = (id, factor) => {
    const c = cards.find((x) => x.id === id);
    if (!c) return;
    const nw = Math.max(70, Math.round(c.w * factor)), nh = Math.max(60, Math.round(c.h * factor));
    const patch = {
      w: nw, h: nh,
      x: Math.round(c.x + (c.w - nw) / 2), y: Math.round(c.y + (c.h - nh) / 2),
    };
    if (c.cw) patch.cw = Math.round(c.cw * factor);
    if (c.ch) patch.ch = Math.round(c.ch * factor);
    if (typeof c.text === "string") patch.fontSize = Math.max(10, Math.round((c.fontSize || 46) * factor));
    patchCard(id, patch);
  };

  /* ---- 接続(右辺中央の○ハンドル) ---- */
  const connDown = (card) => (e) => {
    e.stopPropagation();
    connectRef.current = { fromId: card.id };
    const [x, y] = toCanvas(e);
    setConnectLine({ fromId: card.id, x, y });
    e.currentTarget.setPointerCapture(e.pointerId);
  };
  const connMove = () => (e) => {
    if (!connectRef.current) return;
    const [x, y] = toCanvas(e);
    setConnectLine({ fromId: connectRef.current.fromId, x, y });
  };
  const connUp = () => (e) => {
    if (!connectRef.current) return;
    const from = cards.find((c) => c.id === connectRef.current.fromId);
    const [x, y] = toCanvas(e);
    const target = visible.find((c) =>
      c.id !== from.id && x >= c.x && x <= c.x + c.w && y >= c.y && y <= c.y + c.h);
    connectRef.current = null;
    setConnectLine(null);
    if (!target) return;
    if (from.next) { showToast("1枚のカードから出せる接続は1本までです"); return; }
    if (buildIncoming(topLevel)[target.id]) { showToast("そのカードにはすでに接続が入っています"); return; }
    if (chainFrom(topLevel, target.id).some((c) => c.id === from.id)) { showToast("循環する接続はできません"); return; }
    patchCard(from.id, { next: target.id });
  };

  /* ---- カード追加 ---- */
  const spawnPos = () => {
    const r = viewport.current ? viewport.current.getBoundingClientRect() : { width: 800, height: 600 };
    const cx = (r.width / 2 - pan.x) / scale, cy = (r.height / 2 - pan.y) / scale;
    return [cx - 110 + Math.random() * 60, cy - 100 + Math.random() * 60];
  };
  const addText = (color) => {
    const [x, y] = spawnPos();
    addCards([newCard("text", x, y, { color })]);
    setPalette(false);
    onTutAdvance("color", "done");
  };
  const pickCardColor = (c) => {
    if (palette && palette.cardId) {
      patchCard(palette.cardId, { color: c });
      setPalette(false);
    } else {
      addText(c);
    }
  };
  const addImages = (files) => {
    const arr = Array.from(files);
    if (!arr.length) return;
    const [bx, by] = spawnPos();
    Promise.all(arr.map((f) => new Promise((res) => {
      const rd = new FileReader();
      rd.onload = () => res(rd.result);
      rd.readAsDataURL(f);
    }))).then((srcs) => {
      const created = srcs.map((src, i) => newCard("image", bx + i * 36, by + i * 28, { src }));
      for (let i = 0; i < created.length - 1; i++) created[i].next = created[i + 1].id;
      if (created.length >= 2) created[0].collapsed = true;
      addCards(created);
    });
  };
  const addPdf = (file) => {
    const [x, y] = spawnPos();
    addCards([newCard("pdf", x, y, { fileName: file.name })]);
  };

  const editingId = editStack[editStack.length - 1];
  useEffect(() => {
    if (editingId && !cards.find((c) => c.id === editingId)) setEditStack([]);
  }, [editingId, cards]);
  const viewerChain = viewerHead ? chainFrom(topLevel, viewerHead) : null;

  const DockBtn = ({ label, img, onClick, glow }) => (
    <button onClick={onClick} className={glow ? "tut-glow" : undefined} style={{
      border: "none", background: "none", cursor: "pointer", padding: "4px 10px",
      display: "flex", flexDirection: "column", alignItems: "center", gap: 2, flexShrink: 0,
    }}>
      <img src={img} alt="" draggable={false} style={{ width: 26, height: 26, objectFit: "contain" }} />
      <span style={{ fontSize: 9, color: SUBTLE, letterSpacing: 1, whiteSpace: "nowrap" }}>{label}</span>
    </button>
  );

  return (
    <div
      onPointerDownCapture={mtDown} onPointerUpCapture={mtUp} onPointerCancelCapture={mtUp}
      style={{ position: "fixed", inset: 0, background: CANVAS_BG, overflow: "hidden", fontFamily: "'Hiragino Sans','Noto Sans JP',sans-serif" }}>
      {/* キャンバス */}
      <div ref={viewport}
        onPointerDown={bgDown} onPointerMove={bgMove} onPointerUp={bgUp} onPointerCancel={bgUp}
        style={{ position: "absolute", inset: 0, touchAction: "none", cursor: "grab" }}>
        <div style={{ position: "absolute", left: 0, top: 0, transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})`, transformOrigin: "0 0", transition: zoomAnim ? "transform 0.22s cubic-bezier(0.22,0.61,0.36,1)" : "none", willChange: "transform" }}>
          {/* 接続線 */}
          <svg style={{ position: "absolute", left: 0, top: 0, width: 1, height: 1, overflow: "visible", pointerEvents: "none" }}>
            <defs>
              <marker id="arrowhead" markerWidth="7" markerHeight="7" refX="5" refY="3.5" orient="auto">
                <polygon points="0 0, 7 3.5, 0 7" fill={ACCENT} />
              </marker>
            </defs>
            {visible.map((c) => {
              if (!c.next || hiddenIds.has(c.next) || (c.collapsed && !incoming[c.id])) return null;
              const t = cards.find((x) => x.id === c.next);
              if (!t) return null;
              const x1 = c.x + c.w, y1 = c.y + c.h / 2, x2 = t.x - 6, y2 = t.y + t.h / 2;
              const mx = (x1 + x2) / 2;
              const d = `M ${x1} ${y1} C ${mx} ${y1}, ${mx} ${y2}, ${x2} ${y2}`;
              return (
                <g key={"a" + c.id}>
                  <path d={d} stroke="transparent" strokeWidth="24" fill="none" style={{ pointerEvents: "stroke", cursor: "pointer" }}
                    onPointerDown={(e) => e.stopPropagation()}
                    onClick={(e) => {
                      e.stopPropagation();
                      setConfirmD({ message: "この接続を外しますか?", cb: () => patchCard(c.id, { next: null }) });
                    }} />
                  <path d={d} stroke={ACCENT} strokeWidth="4.5" fill="none" markerEnd="url(#arrowhead)" opacity="0.9" strokeDasharray="0.5 11" strokeLinecap="round" />
                </g>
              );
            })}
            {connectLine && (() => {
              const f = cards.find((c) => c.id === connectLine.fromId);
              if (!f) return null;
              return <line x1={f.x + f.w} y1={f.y + f.h / 2} x2={connectLine.x} y2={connectLine.y}
                stroke={ACCENT} strokeWidth="4" strokeDasharray="8 6" markerEnd="url(#arrowhead)" />;
            })()}
          </svg>

          {/* カード */}
          {visible.map((card) => {
            const isHead = !incoming[card.id] && card.next;
            const chainLen = isHead ? chainFrom(topLevel, card.id).length : 1;
            const kids = childrenOf(cards, card.id);
            return (
              <div key={card.id} style={{ position: "absolute", left: card.x, top: card.y, width: card.w }}>
                {isHead && card.collapsed && (
                  <>
                    <div style={{ position: "absolute", left: 9, top: 9, width: card.w, height: card.h, background: SURFACE, borderRadius: 16, opacity: 0.55 }} />
                    <div style={{ position: "absolute", left: 4.5, top: 4.5, width: card.w, height: card.h, background: SURFACE, borderRadius: 16, opacity: 0.8 }} />
                  </>
                )}
                <div style={{ position: "relative", width: card.w, height: card.h }}
                  onPointerDown={cardDown(card)} onPointerMove={cardMove(card)}
                  onPointerUp={cardUp(card)} onPointerCancel={cardUp(card)}>
                  <div style={{
                    width: "100%", height: "100%", touchAction: "none",
                    boxShadow: hoverTarget === card.id
                      ? "0 8px 24px rgba(15,18,22,0.4), 0 0 0 4px rgba(127,176,204,0.95)"
                      : (card.pinned ? "0 8px 22px rgba(15,18,22,0.4), 0 0 0 3px rgba(244,200,214,0.9)" : "0 8px 24px rgba(15,18,22,0.4)"),
                    borderRadius: 20, overflow: "hidden",
                    border: card.type === "text" && card.color === "transparent" ? `1.5px dashed ${ACCENT}` : "none",
                    cursor: "pointer",
                    background: card.type === "text" && card.color === "transparent" ? "rgba(255,255,255,0.04)" : "#fff",
                  }}>
                    <CardStage card={card} subCards={kids} w={card.w} h={card.h} hint />
                    {/* 右下: 見えるグリップ(四隅=全体拡大) */}
                    {!card.pinned && (
                      <div
                        onPointerDown={resizeDown(card, "se")} onPointerMove={resizeMove(card)}
                        onPointerUp={resizeUp} onPointerCancel={resizeUp}
                        style={{
                          position: "absolute", right: 0, bottom: 0, width: 26, height: 26, touchAction: "none",
                          cursor: "nwse-resize", zIndex: 4,
                          background: "linear-gradient(135deg, transparent 55%, rgba(140,158,175,0.55) 55%)",
                          borderTopLeftRadius: 8,
                        }} />
                    )}
                    {card.pinned && <div style={{ position: "absolute", left: 5, top: 4, zIndex: 2 }}><UIcon name="pin" size={14} color={PINK} /></div>}
                    {isHead && card.collapsed && (
                      <div style={{
                        position: "absolute", left: 6, bottom: 6, background: ACCENT_DEEP, color: "#fff",
                        borderRadius: 10, fontSize: 11, fontWeight: 800, padding: "2px 8px", zIndex: 2,
                      }}>{chainLen}枚</div>
                    )}
                  </div>
                  {/* リサイズ領域: 4辺(枠だけ・中身固定) + 四隅(全体拡大)。overflow外に配置 */}
                  {!card.pinned && [
                    ["n", { left: 18, right: 18, top: -5, height: 13, cursor: "ns-resize" }],
                    ["s", { left: 18, right: 30, bottom: -5, height: 13, cursor: "ns-resize" }],
                    ["w", { top: 18, bottom: 18, left: -5, width: 13, cursor: "ew-resize" }],
                    ["e", { top: 18, bottom: 30, right: -5, width: 13, cursor: "ew-resize" }],
                    ["nw", { top: -5, left: -5, width: 20, height: 20, cursor: "nwse-resize" }],
                    ["ne", { top: -5, right: -5, width: 20, height: 20, cursor: "nesw-resize" }],
                    ["sw", { bottom: -5, left: -5, width: 20, height: 20, cursor: "nesw-resize" }],
                  ].map(([k, pos]) => (
                    <div key={k}
                      onPointerDown={resizeDown(card, k)} onPointerMove={resizeMove(card)}
                      onPointerUp={resizeUp} onPointerCancel={resizeUp}
                      style={{ position: "absolute", touchAction: "none", zIndex: 5, ...pos }} />
                  ))}
                  {/* 接続ハンドル: 右辺中央の○(カード枠の外に半分はみ出す) */}
                  <div
                    onPointerDown={connDown(card)} onPointerMove={connMove(card)}
                    onPointerUp={connUp(card)} onPointerCancel={connUp(card)}
                    title="ドラッグして他のカードと接続"
                    style={{
                      position: "absolute", right: -12, top: "50%", marginTop: -12,
                      width: 24, height: 24, borderRadius: 12, touchAction: "none",
                      background: SURFACE, border: `2px solid ${ACCENT_DEEP}`,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      fontSize: 10, color: ACCENT_DEEP, cursor: "crosshair", zIndex: 3,
                      boxShadow: "0 2px 8px rgba(15,18,22,0.4)",
                    }}><UIcon name="link" size={13} color="#fff" /></div>
                </div>
                {card.tags.length > 0 && (
                  <div style={{ display: "flex", gap: 4, flexWrap: "wrap", marginTop: 5 }}>
                    {card.tags.map((t) => (
                      <span key={t} style={{ background: "rgba(255,255,255,0.12)", color: LIGHT_TXT, fontSize: 10, borderRadius: 8, padding: "1px 7px" }}>#{t}</span>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* 上部バー(Procreate風: テキストリンクのツール) */}
      <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 52, display: "flex", alignItems: "center", padding: "0 14px", zIndex: 11, pointerEvents: "none" }}>
        <button onClick={onBack} style={{ pointerEvents: "auto", background: "none", border: "none", color: LIGHT_TXT, cursor: "pointer", fontSize: 22, flexShrink: 0, padding: "4px 8px" }}>‹</button>
        <div style={{ marginLeft: 4, fontSize: 13, lineHeight: 1.3, letterSpacing: 0.5, overflow: "hidden", flexShrink: 1 }}>
          <span style={{ fontWeight: 700, color: LIGHT_TXT, whiteSpace: "nowrap", textOverflow: "ellipsis", overflow: "hidden", display: "inline-block", maxWidth: "30vw", verticalAlign: "bottom" }}>{note.name}</span>
        </div>
        <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: 4, pointerEvents: "auto", flexShrink: 0 }}>
          {[
            ["テキスト", () => { setPalette((p) => !p); onTutAdvance("text", "color"); }, tut === "text"],
            ["画像", () => fileInput.current.click(), false],
            ["カメラ", () => camInput.current.click(), false],
            ["PDF", () => pdfInput.current.click(), false],
          ].map(([label, fn, glow]) => (
            <button key={label} onClick={fn} className={glow ? "tut-glow" : undefined} style={{
              background: "none", border: "none", color: LIGHT_TXT, cursor: "pointer",
              fontSize: 13, fontWeight: 600, letterSpacing: 0.5, padding: "8px 8px", whiteSpace: "nowrap",
            }}>{label}</button>
          ))}
          <button onClick={() => { const [x, y] = spawnPos(); addCards([newCard("text", x, y, { color: null })]); }}
            title="カードを追加" style={{
              width: 34, height: 34, borderRadius: 17, marginLeft: 2,
              background: "rgba(255,255,255,0.12)", border: "1px solid rgba(255,255,255,0.25)",
              color: LIGHT_TXT, fontSize: 19, cursor: "pointer", flexShrink: 0,
            }}>＋</button>
        </div>
      </div>

      {/* ゴミ箱(ドラッグ時だけ上中央に出現) */}
      <div ref={trashRef} style={{
        position: "absolute", left: "50%", transform: "translateX(-50%)", top: 56, zIndex: 10,
        display: "flex", alignItems: "center", gap: 6, padding: "7px 16px", borderRadius: 18,
        border: trashHot ? `2px dashed #e89aa4` : `1.5px dashed rgba(255,255,255,0.22)`,
        background: trashHot ? "rgba(232,154,164,0.2)" : "rgba(255,255,255,0.06)",
        color: trashHot ? "#f3c3ca" : "rgba(255,255,255,0.5)", fontSize: 11, transition: "all .15s",
        opacity: dragRef.current ? 1 : 0.5, pointerEvents: "none",
      }}>
        <UIcon name="trash" size={14} color={trashHot ? "#f3c3ca" : "rgba(255,255,255,0.5)"} /> {trashHot ? "はなして削除" : "ここへドラッグで削除"}
      </div>

      {/* 資料箱・共有(左下にコンパクトに常設・ドロップ先) */}
      <div style={{ position: "absolute", left: 12, bottom: 14, display: "flex", gap: 8, zIndex: 10 }}>
        <div ref={boxBtnRef} onClick={() => setBoxOpen(true)} style={{
          display: "flex", alignItems: "center", gap: 5, cursor: "pointer", padding: "8px 12px", borderRadius: 16,
          background: boxHot ? ACCENT_SOFT : "rgba(255,255,255,0.1)",
          border: boxHot ? `2px dashed ${ACCENT_DEEP}` : "1px solid rgba(255,255,255,0.18)",
        }}>
          <span style={{ fontSize: 12, color: boxHot ? ACCENT_DEEP : LIGHT_TXT, fontWeight: 600, whiteSpace: "nowrap" }}>資料箱</span>
        </div>
        <div ref={shareBtnRef} onClick={() => showToast("カードをここへドラッグすると他のノートへ送れます")} style={{
          display: "flex", alignItems: "center", gap: 5, cursor: "pointer", padding: "8px 12px", borderRadius: 16,
          background: shareHot ? ACCENT_SOFT : "rgba(255,255,255,0.1)",
          border: shareHot ? `2px dashed ${ACCENT_DEEP}` : "1px solid rgba(255,255,255,0.18)",
        }}>
          <span style={{ fontSize: 12, color: shareHot ? ACCENT_DEEP : LIGHT_TXT, fontWeight: 600, whiteSpace: "nowrap" }}>共有</span>
        </div>
      </div>

      {/* ズームコントロール(右下) */}
      <div style={{
        position: "absolute", right: 12, bottom: 14, zIndex: 10,
        display: "flex", flexDirection: "column", alignItems: "center",
        background: "rgba(255,255,255,0.1)", borderRadius: 16, border: "1px solid rgba(255,255,255,0.18)", overflow: "hidden",
      }}>
        <button onClick={() => zoomButton(1.25)} title="拡大" style={{ width: 38, height: 34, border: "none", borderBottom: "1px solid rgba(255,255,255,0.15)", background: "none", color: LIGHT_TXT, fontSize: 18, cursor: "pointer" }}>＋</button>
        <button onClick={() => { setZoomAnim(true); clearTimeout(zoomAnimTimer.current); zoomAnimTimer.current = setTimeout(() => setZoomAnim(false), 260); setScale(1); setPan({ x: 0, y: 0 }); }} title="100%に戻す" style={{ width: 38, height: 26, border: "none", borderBottom: "1px solid rgba(255,255,255,0.15)", background: "none", color: scale !== 1 ? ACCENT : "rgba(255,255,255,0.5)", fontSize: 9, fontWeight: 700, cursor: "pointer" }}>{Math.round(scale * 100)}%</button>
        <button onClick={() => zoomButton(0.8)} title="縮小" style={{ width: 38, height: 34, border: "none", background: "none", color: LIGHT_TXT, fontSize: 18, cursor: "pointer" }}>−</button>
      </div>

      {/* 色パレット(テキスト追加時・上部から) */}
      {palette && (
        <div className={tut === "color" ? "tut-glow" : undefined} style={{
          position: "absolute", top: 58, right: 14, zIndex: 20,
          background: SURFACE, borderRadius: 18, padding: 14,
          boxShadow: "0 14px 40px rgba(0,0,0,0.6)", width: 196, border: `1px solid ${BORDER}`,
        }}>
          <div style={{ fontSize: 11, color: SUBTLE, marginBottom: 8, textAlign: "center", letterSpacing: 1 }}>
            {palette.cardId ? "カードの色を変更" : "カードの色を選択"}
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 10 }}>
            {[
              "#ffffff", "#f1f3f5", "#fce7ee",
              "#f8d9e4", "#fdf3e3", "#f7ecd2",
              "#e7f3ec", "#d9ecdf", "#e8f3fa",
              "#d6e9f5", "#efe9f7", "#e2d9f1",
              "#3f4750", "transparent",
            ].map((c) => (
              <button key={c} onClick={() => pickCardColor(c)} style={{
                width: 54, height: 40, borderRadius: 10, cursor: "pointer",
                border: `1px solid ${c === "#ffffff" || c === "transparent" ? "#d4dae1" : "rgba(0,0,0,0.06)"}`,
                background: c === "transparent" ? "repeating-linear-gradient(45deg, #fff 0 6px, #eef1f4 6px 12px)" : c,
                position: "relative", padding: 0,
              }}>
                {c === "transparent" && (
                  <svg width="54" height="40" style={{ position: "absolute", inset: 0 }}>
                    <line x1="7" y1="7" x2="47" y2="33" stroke="#b9c2cb" strokeWidth="1.5" />
                    <line x1="47" y1="7" x2="7" y2="33" stroke="#b9c2cb" strokeWidth="1.5" />
                  </svg>
                )}
              </button>
            ))}
            <label style={{
              width: 54, height: 40, borderRadius: 10, cursor: "pointer", overflow: "hidden",
              border: `1px solid #d4dae1`, position: "relative", display: "flex",
              alignItems: "center", justifyContent: "center",
              background: "conic-gradient(#f8d9e4, #f7ecd2, #d9ecdf, #d6e9f5, #e2d9f1, #f8d9e4)",
            }}>
              <input type="color" defaultValue="#f8d9e4"
                onChange={(e) => pickCardColor(e.target.value)}
                style={{ position: "absolute", inset: 0, opacity: 0, cursor: "pointer" }} />
            </label>
          </div>
        </div>
      )}

      {/* 長押しメニュー */}
      {menu && (() => {
        const c = cards.find((x) => x.id === menu.cardId);
        if (!c) return null;
        return (
          <div style={{
            position: "absolute", left: Math.min(menu.vx, window.innerWidth - 175), top: Math.min(menu.vy, window.innerHeight - 230),
            background: SURFACE, borderRadius: 14, boxShadow: "0 10px 30px rgba(15,18,22,0.5)", zIndex: 50,
            overflow: "hidden", width: 165,
          }}>
            {(() => {
              const incomingTop = buildIncoming(topLevel);
              const isHead = !incomingTop[c.id] && c.next;       // 連結チェーンの先頭
              const isMerged = isHead && c.collapsed;            // まとめ済み
              const items = [];
              if (isMerged) {
                // まとめ済み: グループごと複製/削除
                items.push(["copy", "まとめて複製", () => duplicateChain(c.id)]);
                items.push(["unlock", "まとめを解除", () => patchCard(c.id, { collapsed: false })]);
                items.push(["trash", "まとめて削除", () => deleteChain(c.id)]);
              } else if (isHead) {
                // 連結済みだがバラバラ: 整列ボタン
                items.push(["copy", "複製", () => addCards(cloneBundleOf(c.id, [c.x + 30, c.y + 30]))]);
                items.push(["align", "整列", () => alignChain(c.id)]);
                items.push(["link", "まとめる", () => patchCard(c.id, { collapsed: true })]);
                items.push(["pin", c.pinned ? "ピン解除" : "ピン留め", () => patchCard(c.id, { pinned: !c.pinned })]);
                items.push(["palette", "カードの色", () => setPalette({ cardId: c.id })]);
                items.push(["trash", "削除", () => removeDeep(c.id)]);
              } else {
                // 単独カード(画像・テキスト・PDFすべて)
                items.push(["copy", "複製", () => addCards(cloneBundleOf(c.id, [c.x + 30, c.y + 30]))]);
                items.push(["bigger", "大きくする", () => scaleCard(c.id, 1.25)]);
                items.push(["smaller", "小さくする", () => scaleCard(c.id, 0.8)]);
                items.push(["pin", c.pinned ? "ピン解除" : "ピン留め", () => patchCard(c.id, { pinned: !c.pinned })]);
                items.push(["palette", "カードの色", () => setPalette({ cardId: c.id })]);
                items.push(["tag", "タグを追加", () => {
                  setPromptD({
                    title: "タグ名を入力", initial: "",
                    cb: (t) => { if (!c.tags.includes(t)) patchCard(c.id, { tags: [...c.tags, t] }); },
                  });
                }]);
                items.push(["trash", "削除", () => removeDeep(c.id)]);
              }
              return items;
            })().map(([icon, label, fn]) => (
              <button key={label} onClick={() => { fn(); setMenu(null); }} style={{
                display: "flex", alignItems: "center", gap: 10, width: "100%", padding: "11px 14px", border: "none", background: "none",
                textAlign: "left", fontSize: 14, cursor: "pointer", borderBottom: `1px solid ${BORDER}`, color: icon === "trash" ? "#e58a94" : INK,
              }}><UIcon name={icon} size={17} color={icon === "trash" ? "#e58a94" : SUBTLE} /> {label}</button>
            ))}
          </div>
        );
      })()}

      {/* 資料箱: 格納先選択 */}
      {boxDrop && (() => {
        const c = cards.find((x) => x.id === boxDrop);
        if (!c) return null;
        const storeInto = (fileId) => {
          const bundle = cloneBundleOf(c.id);
          setMaterialBox((mb) => mb.map((f) => (f.id === fileId ? { ...f, items: [...f.items, { id: uid(), cards: bundle }] } : f)));
          removeDeep(c.id);
          setBoxDrop(null);
          showToast("資料箱に格納しました");
        };
        return (
          <div style={{ position: "fixed", inset: 0, background: "rgba(20,23,28,0.45)", zIndex: 80, display: "flex", alignItems: "center", justifyContent: "center" }}
            onClick={() => setBoxDrop(null)}>
            <div onClick={(e) => e.stopPropagation()} style={{ background: SURFACE, borderRadius: 18, width: 290, maxHeight: "70%", overflowY: "auto", boxShadow: "0 18px 50px rgba(0,0,0,0.45)" }}>
              <div style={{ padding: "16px 18px 8px", fontWeight: 700, fontSize: 14, color: INK, textAlign: "center" }}>どのファイルに格納しますか?</div>
              {materialBox.map((f) => (
                <button key={f.id} onClick={() => storeInto(f.id)} style={{
                  display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "12px 18px",
                  border: "none", borderTop: `1px solid ${BORDER}`, background: "none", cursor: "pointer", fontSize: 14, color: INK,
                }}>
                  <UIcon name="folder" size={16} color={SUBTLE} /> <span style={{ flex: 1, textAlign: "left" }}>{f.name}</span>
                  <span style={{ fontSize: 11, color: SUBTLE }}>{f.items.length}枚</span>
                </button>
              ))}
              <button onClick={() => {
                setPromptD({
                  title: "新しいファイル名", initial: `ファイル${materialBox.length + 1}`,
                  cb: (name) => {
                    const bundle = cloneBundleOf(c.id);
                    setMaterialBox((mb) => [...mb, { id: uid(), name, items: [{ id: uid(), cards: bundle }] }]);
                    removeDeep(c.id);
                    showToast(`「${name}」を作成して格納しました`);
                  },
                });
                setBoxDrop(null);
              }} style={{
                display: "block", width: "100%", padding: "13px 18px", border: "none", borderTop: `1px solid ${BORDER}`,
                background: ACCENT_SOFT, color: ACCENT_DEEP, fontWeight: 700, fontSize: 14, cursor: "pointer",
                borderRadius: "0 0 18px 18px",
              }}>＋ 新しいファイルを作って格納</button>
            </div>
          </div>
        );
      })()}

      {/* 共有: 送信先ノート選択 */}
      {shareDrop && (() => {
        const c = cards.find((x) => x.id === shareDrop);
        if (!c) return null;
        return (
          <div style={{ position: "fixed", inset: 0, background: "rgba(20,23,28,0.45)", zIndex: 80, display: "flex", alignItems: "center", justifyContent: "center" }}
            onClick={() => setShareDrop(null)}>
            <div onClick={(e) => e.stopPropagation()} style={{ background: SURFACE, borderRadius: 18, width: 300, maxHeight: "72%", overflowY: "auto", boxShadow: "0 18px 50px rgba(0,0,0,0.45)" }}>
              <div style={{ padding: "16px 18px 10px", fontWeight: 700, fontSize: 14, color: INK, textAlign: "center" }}>どのノートへ送りますか?</div>
              {groups.map((g) => (
                <div key={g.id}>
                  <div style={{ padding: "8px 18px 4px", fontSize: 11, color: SUBTLE, fontWeight: 700, letterSpacing: 1, borderTop: `1px solid ${BORDER}` }}>{g.name}</div>
                  {g.notes.filter((n) => !(g.id === group.id && n.id === note.id)).map((n) => (
                    <button key={n.id} onClick={() => {
                      onSendCard(g.id, n.id, cloneBundleOf(c.id, [140 + Math.random() * 80, 140 + Math.random() * 80]));
                      setShareDrop(null);
                      showToast(`「${n.name}」へ送りました`);
                    }} style={{
                      display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "10px 18px 10px 26px",
                      border: "none", background: "none", cursor: "pointer", fontSize: 13, color: INK,
                    }}>
                      <UIcon name="note" size={16} color={SUBTLE} /> <span style={{ flex: 1, textAlign: "left" }}>{n.name}</span>
                    </button>
                  ))}
                  {g.notes.filter((n) => !(g.id === group.id && n.id === note.id)).length === 0 && (
                    <div style={{ padding: "4px 18px 10px 26px", fontSize: 11, color: "#c3cad2" }}>送れるノートがありません</div>
                  )}
                </div>
              ))}
            </div>
          </div>
        );
      })()}

      {/* 資料箱パネル */}
      {boxOpen && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(20,23,28,0.45)", zIndex: 80 }}
          onClick={() => setBoxOpen(false)}>
          <div onClick={(e) => e.stopPropagation()} style={{
            position: "absolute", right: 0, top: 0, bottom: 0, width: 285, background: SURFACE,
            boxShadow: "-8px 0 30px rgba(0,0,0,0.4)", display: "flex", flexDirection: "column",
          }}>
            <div style={{ padding: "16px 16px 10px", display: "flex", alignItems: "center", gap: 8, borderBottom: `1px solid ${BORDER}` }}>
              <img src={ICON_BOX} alt="" style={{ width: 22, height: 22, objectFit: "contain" }} />
              <span style={{ fontWeight: 700, color: INK, flex: 1 }}>資料箱</span>
              <button onClick={() => setBoxOpen(false)} style={{ border: "none", background: "none", color: SUBTLE, cursor: "pointer", display: "inline-flex" }}><UIcon name="close" size={18} /></button>
            </div>
            <div style={{ flex: 1, overflowY: "auto", padding: 12 }}>
              {materialBox.length === 0 && (
                <div style={{ color: SUBTLE, fontSize: 12, textAlign: "center", marginTop: 30, lineHeight: 1.8 }}>
                  まだファイルがありません。<br />カードを「資料箱」へ<br />ドラッグして格納できます。
                </div>
              )}
              {materialBox.map((f) => (
                <div key={f.id} style={{ marginBottom: 14, border: `1px solid ${BORDER}`, borderRadius: 14, overflow: "hidden" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "9px 12px", background: SURFACE_2 }}>
                    <UIcon name="folder" size={16} color={SUBTLE} /> <span style={{ flex: 1, fontSize: 13, fontWeight: 700, color: INK }}>{f.name}</span>
                    <button onClick={() => setMaterialBox((mb) => mb.filter((x) => x.id !== f.id))}
                      style={{ border: "none", background: "none", color: SUBTLE, cursor: "pointer", fontSize: 13 }}><UIcon name="trash" size={15} /></button>
                  </div>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 8, padding: 10 }}>
                    {f.items.length === 0 && <span style={{ fontSize: 11, color: "#c3cad2" }}>空のファイル</span>}
                    {f.items.map((it) => (
                      <div key={it.id} style={{ width: 110 }}>
                        <div style={{ borderRadius: 10, overflow: "hidden", border: `1px solid ${BORDER}` }}>
                          <CardStage card={it.cards[0]} subCards={it.cards.slice(1)} w={110} h={82} />
                        </div>
                        <div style={{ display: "flex", gap: 4, marginTop: 4 }}>
                          <button onClick={() => {
                            const [x, y] = spawnPos();
                            addCards(cloneBundle(it.cards, [x, y]));
                            setBoxOpen(false);
                            showToast("キャンバスに取り出しました");
                          }} style={{ flex: 1, border: "none", borderRadius: 8, background: ACCENT_SOFT, color: ACCENT_DEEP, fontSize: 10, fontWeight: 700, padding: "4px 0", cursor: "pointer" }}>取り出す</button>
                          <button onClick={() => setMaterialBox((mb) => mb.map((x) => (x.id === f.id ? { ...x, items: x.items.filter((cc) => cc.id !== it.id) } : x)))}
                            style={{ border: "none", borderRadius: 8, background: SURFACE_2, color: SUBTLE, fontSize: 10, padding: "4px 7px", cursor: "pointer" }}><UIcon name="trash" size={13} /></button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* スワイプ閲覧 */}
      {viewerChain && viewerChain.length > 0 && (
        <SwipeViewer chain={viewerChain} allCards={cards} onClose={() => setViewerHead(null)}
          onEdit={(id) => { setViewerHead(null); setEditStack([id]); }}
          onDuplicate={(id) => {
            // チェーン内の1枚を複製し、その直後に挿入
            const orig = cards.find((c) => c.id === id);
            if (!orig) return;
            const bundle = collectBundle(cards, id);
            const m = {};
            bundle.forEach((b) => { m[b.id] = uid(); });
            const clones = bundle.map((b) => ({
              ...b, id: m[b.id], parentId: b.parentId ? m[b.parentId] : null,
              next: null, collapsed: false,
              strokes: b.strokes.map((st) => ({ ...st, id: uid(), points: st.points.map((p) => [...p]) })),
              tags: [...b.tags],
            }));
            const newId = m[id];
            // origの次に挿入(orig→clone→旧next)
            setCards((cs) => {
              const updated = cs.map((c) => c.id === id ? { ...c, next: newId } : c);
              const cloneHead = clones.find((cl) => cl.id === newId);
              if (cloneHead) cloneHead.next = orig.next || null;
              return [...updated, ...clones];
            });
            showToast("カードを複製しました");
          }}
          onDelete={(id) => { removeDeep(id); }} />
      )}

      {/* カードエディタ(階層スタック: 子カードを開くと深くなる) */}
      {editStack.map((id, i) => {
        if (i !== editStack.length - 1) return null;
        // 最上位(depth1)のカードが連結チェーンの一部なら、左右スワイプで前後へ移動できる
        let chainIds = null;
        if (i === 0) {
          const cur = cards.find((c) => c.id === id);
          if (cur && !cur.parentId) {
            // チェーンの先頭を探す
            const incTop = buildIncoming(topLevel);
            let head = id;
            const guard = new Set();
            while (incTop[head] && !guard.has(head)) { guard.add(head); head = incTop[head]; }
            const ch = chainFrom(topLevel, head);
            if (ch.length >= 2) chainIds = ch.map((c) => c.id);
          }
        }
        return (
          <CardEditor key={id} cardId={id} cards={cards} depth={i + 1}
            patchCard={patchCard} addCards={addCards} removeDeep={removeDeep}
            detachChild={detachChild} onUndo={undo} onRedo={redo}
            chainIds={chainIds}
            onNavigate={(cid) => setEditStack((st) => [...st.slice(0, -1), cid])}
            pushEdit={(cid) => setEditStack((st) => [...st, cid])}
            onClose={() => setEditStack((st) => st.slice(0, -1))}
            showToast={showToast} />
        );
      })}

      {/* チュートリアル */}
      <TutStyle />
      {tut === "text" && (
        <TutBubble no={4} title="カードを作ろう"
          desc={<>下の「テキスト」をタップしてみよう。</>}
          onSkip={onTutEnd} style={{ bottom: 92 }} />
      )}
      {tut === "color" && (
        <TutBubble no={5} title="カードの色を選ぼう"
          desc={<>すきな色をタップすると、キャンバスにカードが置かれるよ。</>}
          onSkip={onTutEnd} style={{ top: 56 }} />
      )}
      {tut === "done" && (
        <TutBubble title="カード完成!"
          desc={<>ダブルタップで中を編集、ドラッグで移動。右の○から他のカードと接続もできるよ。下のドックから資料箱・共有も使ってみてね。</>}
          style={{ top: "36%" }}
          btn={
            <button onClick={onTutEnd} style={{ border: "none", background: ACCENT_DEEP, color: "#fff", borderRadius: 12, padding: "6px 16px", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
              はじめる
            </button>
          } />
      )}

      {/* トースト・ダイアログ */}
      <Toast msg={toast} />
      {promptD && (
        <PromptDialog title={promptD.title} initial={promptD.initial}
          onOk={promptD.cb} onClose={() => setPromptD(null)} />
      )}
      {confirmD && (
        <ConfirmDialog message={confirmD.message}
          onOk={confirmD.cb} onClose={() => setConfirmD(null)} />
      )}

      {/* 隠しinput */}
      <input ref={fileInput} type="file" accept="image/*" multiple style={{ display: "none" }}
        onChange={(e) => { addImages(e.target.files); e.target.value = ""; }} />
      <input ref={camInput} type="file" accept="image/*" capture="environment" style={{ display: "none" }}
        onChange={(e) => { addImages(e.target.files); e.target.value = ""; }} />
      <input ref={pdfInput} type="file" accept="application/pdf" style={{ display: "none" }}
        onChange={(e) => { if (e.target.files[0]) addPdf(e.target.files[0]); e.target.value = ""; }} />
    </div>
  );
}

/* ============================================================
   永続化(localStorage)
   旧形式のデータは子カード形式に自動移行
   ============================================================ */
const STORAGE_KEY = "teddynote:data";
const migrateAll = (data) => {
  // v1: groups配列のみ / v2: {groups, materialBox(cards)} / v3: 子カード形式 {v:3,...}
  if (Array.isArray(data)) data = { groups: data, materialBox: [] };
  if (data.v === 3) return data;
  const groups = (data.groups || []).map((g) => ({
    ...g,
    notes: (g.notes || []).map((n) => ({ ...n, cards: (n.cards || []).flatMap(migrateCard) })),
  }));
  const materialBox = (data.materialBox || []).map((f) => ({
    id: f.id, name: f.name,
    items: f.items
      ? f.items
      : (f.cards || []).map((c) => ({ id: uid(), cards: migrateCard(c) })),
  }));
  return { v: 3, groups, materialBox, bgImage: data.bgImage };
};
const persistence = {
  load: async () => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? migrateAll(JSON.parse(raw)) : null;
    } catch (e) { return null; }
  },
  save: async (groups, materialBox, bgImage) => {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify({ v: 3, groups, materialBox, bgImage })); return true; }
    catch (e) { console.error("save failed", e); return false; }
  },
};

const DEFAULT_GROUPS = () => [
  { id: uid(), name: "国語", notes: [] },
  { id: uid(), name: "数学", notes: [] },
  { id: uid(), name: "化学", notes: [] },
  { id: uid(), name: "修学旅行のアルバム", notes: [] },
];

/* ノートの中身を小さく描く(ホームのノートタイル用) */
function MiniPreview({ cards }) {
  const tops = cards.filter((c) => !c.parentId).slice(0, 16);
  const k = 0.11;
  return (
    <div style={{ height: 88, borderRadius: 12, background: CANVAS_BG, position: "relative", overflow: "hidden" }}>
      {tops.map((c) => (
        <div key={c.id} style={{
          position: "absolute", left: 10 + c.x * k, top: 6 + c.y * k,
          width: Math.max(12, c.w * k), height: Math.max(9, c.h * k), borderRadius: 3,
          background: c.type === "image" ? "#b9c8d4" : c.type === "pdf" ? "#f3dede" :
            (c.color && c.color !== "transparent" ? c.color : "#f4f6f8"),
          border: c.color === "transparent" ? "1px dashed rgba(255,255,255,0.45)" : "none",
          boxSizing: "border-box", opacity: 0.95,
        }} />
      ))}
      {tops.length === 0 && (
        <span style={{
          position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
          color: "rgba(255,255,255,0.32)", fontSize: 10, letterSpacing: 3, fontFamily: SERIF,
        }}>empty</span>
      )}
    </div>
  );
}

/* ============================================================
   ホーム画面(グループ=チップ / ノート=プレビュー付きグリッド)
   ============================================================ */
export default function App() {
  const [entered, setEntered] = useState(false);
  const [materialBox, setMaterialBox] = useState([]);
  const [groups, setGroups] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [saveState, setSaveState] = useState("idle");
  const [selGroup, setSelGroup] = useState(null);
  const [openNote, setOpenNote] = useState(null);
  const [dialog, setDialog] = useState(null);
  const [renameD, setRenameD] = useState(null);
  const [tut, setTut] = useState(null); // チュートリアル: rename→addNote→openNote→text→color→done
  const [bgImage, setBgImage] = useState(DEFAULT_BG); // トップ/ノート選択画面の背景
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [fxOn, setFxOn] = useState(getFxEnabled());
  const [appToast, setAppToast] = useState("");
  const appToastTimer = useRef(null);
  const showAppToast = (m) => {
    setAppToast(m);
    clearTimeout(appToastTimer.current);
    appToastTimer.current = setTimeout(() => setAppToast(""), 2600);
  };
  useEffect(() => {
    // どのボタンを押しても「カツッ」+バイブ(設定でオフ可)
    const onDown = (e) => {
      const btn = e.target && e.target.closest && e.target.closest("button,[role=button]");
      if (btn && !btn.disabled) feedback();
    };
    document.addEventListener("pointerdown", onDown, true);
    return () => document.removeEventListener("pointerdown", onDown, true);
  }, []);
  const bgInput = useRef(null);
  const tutSeen = useRef(false);
  const tutStarted = useRef(false);
  const saveTimer = useRef(null);

  const advanceTut = (from, to) => setTut((t) => (t === from ? to : t));
  const endTut = () => {
    setTut(null);
    tutSeen.current = true;
    try { localStorage.setItem("teddynote:tut", "1"); } catch (e) {}
  };

  // 初回だけチュートリアルを自動開始
  useEffect(() => {
    try { if (localStorage.getItem("teddynote:tut")) tutSeen.current = true; } catch (e) {}
  }, []);
  useEffect(() => {
    if (entered && loaded && !tutSeen.current && !tutStarted.current) {
      tutStarted.current = true;
      setTut("rename");
    }
  }, [entered, loaded]);

  useEffect(() => {
    (async () => {
      const data = await persistence.load();
      if (data) {
        const gs = Array.isArray(data.groups) ? data.groups : [];
        const untouched = gs.length > 0 && gs.every((g) => !g.notes || g.notes.length === 0);
        setGroups(gs.length && !untouched ? gs : DEFAULT_GROUPS());
        setMaterialBox(Array.isArray(data.materialBox) ? data.materialBox : []);
        if (typeof data.bgImage === "string") setBgImage(data.bgImage);
      } else {
        setGroups(DEFAULT_GROUPS());
      }
      setLoaded(true);
    })();
  }, []);

  useEffect(() => {
    if (!loaded) return;
    setSaveState("saving");
    clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(async () => {
      const ok = await persistence.save(groups, materialBox, bgImage);
      setSaveState(ok ? "saved" : "error");
    }, 800);
    return () => clearTimeout(saveTimer.current);
  }, [groups, materialBox, bgImage, loaded]);

  const group = groups.find((g) => g.id === (openNote ? openNote.groupId : selGroup));
  const note = openNote && group ? group.notes.find((n) => n.id === openNote.noteId) : null;

  const updateNoteCards = (cards) => {
    setGroups((gs) => gs.map((g) =>
      g.id !== openNote.groupId ? g :
      { ...g, notes: g.notes.map((n) => (n.id !== openNote.noteId ? n : { ...n, cards })) }));
  };
  const sendCardToNote = (gid, nid, bundle) => {
    setGroups((gs) => gs.map((g) =>
      g.id !== gid ? g :
      { ...g, notes: g.notes.map((n) => (n.id !== nid ? n : { ...n, cards: [...n.cards, ...bundle] })) }));
  };

  const SaveBadge = () => (
    <div style={{
      position: "fixed", bottom: 8, left: 10, zIndex: 400,
      fontSize: 10, color: saveState === "error" ? "#d04030" : SUBTLE,
      background: SURFACE, padding: "2px 10px", borderRadius: 10, pointerEvents: "none", border: `1px solid ${BORDER}`,
    }}>
      {saveState === "saving" ? "保存中…" : saveState === "saved" ? "保存済み" : saveState === "error" ? "保存に失敗しました" : ""}
    </div>
  );

  if (!entered) return <LoginGate onEnter={() => setEntered(true)} />;

  if (!loaded) {
    return (
      <div style={{ position: "fixed", inset: 0, background: CANVAS_BG, display: "flex", alignItems: "center", justifyContent: "center", color: SUBTLE, fontSize: 14 }}>
        読み込み中…
      </div>
    );
  }

  if (openNote && note && group) {
    return (
      <>
        <CanvasScreen note={note} group={group} groups={groups}
          materialBox={materialBox} setMaterialBox={setMaterialBox}
          onSendCard={sendCardToNote}
          tut={tut} onTutAdvance={advanceTut} onTutEnd={endTut}
          onUpdateCards={updateNoteCards} onBack={() => setOpenNote(null)} />
        <SaveBadge />
      </>
    );
  }

  const effSel = selGroup ?? (groups[0] ? groups[0].id : null);
  const selG = groups.find((g) => g.id === effSel);

  return (
    <div style={{
      position: "fixed", inset: 0, overflowY: "auto",
      fontFamily: "'Hiragino Sans','Noto Sans JP',sans-serif",
      background: bgImage
        ? `linear-gradient(rgba(154,154,157,0.62), rgba(154,154,157,0.72)), url(${bgImage}) center/cover fixed no-repeat`
        : TOP_BG,
    }}>
      <div style={{ maxWidth: 1120, margin: "0 auto", padding: "max(36px, 4vh) clamp(18px, 4vw, 48px) 80px" }}>

        {/* 設定ボタン(右上) */}
        <button onClick={() => setSettingsOpen(true)} title="設定" style={{
          position: "fixed", top: 14, right: 14, zIndex: 30,
          width: 38, height: 38, borderRadius: 19, cursor: "pointer",
          background: "rgba(255,255,255,0.4)", border: "1px solid rgba(255,255,255,0.5)",
          color: TOP_INK, fontSize: 17, backdropFilter: "blur(4px)",
        }}><UIcon name="gear" size={18} color={TOP_INK} /></button>

        {/* ブランド */}
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
          <div style={{ marginTop: 8, fontSize: 26, color: TOP_INK, fontFamily: "'Hiragino Sans','Noto Sans JP',sans-serif", fontWeight: 800, letterSpacing: "0.16em", textIndent: "0.16em" }}>onote</div>
          <div style={{ marginTop: 6, fontSize: 9.5, color: TOP_SUBTLE, letterSpacing: "0.3em", textIndent: "0.3em" }}>〜 CARDS ON MY CANVAS 〜</div>
        </div>

        {/* 検索 */}
        <div style={{
          margin: "24px auto 0", maxWidth: 420, display: "flex", alignItems: "center", gap: 8,
          background: TOP_SURFACE, border: `1px solid ${TOP_BORDER}`, borderRadius: 999,
          padding: "10px 18px", color: TOP_SUBTLE, fontSize: 12.5, letterSpacing: 1,
        }}>
          ノートを検索する
        </div>

        {/* グループ(チップ) */}
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", justifyContent: "center", marginTop: 26 }}>
          {groups.map((g) => {
            const on = effSel === g.id;
            return (
              <button key={g.id} onClick={() => setSelGroup(g.id)}
                className={tut === "rename" && on ? "tut-glow" : undefined}
                style={{
                border: on ? `1.5px solid ${TOP_ACTIVE}` : `1.5px solid ${TOP_BORDER}`,
                background: on ? TOP_ACTIVE : TOP_SURFACE,
                color: on ? "#f3f3f4" : TOP_INK,
                borderRadius: 999, padding: "9px 18px", fontSize: 13, cursor: "pointer",
                letterSpacing: 1, fontWeight: on ? 700 : 500, transition: "all .15s",
                boxShadow: on ? "0 4px 12px rgba(40,42,48,0.3)" : "0 1px 3px rgba(40,42,48,0.12)",
                display: "flex", alignItems: "center", gap: 6,
              }}>
                {g.name}
                {on && (
                  <span onClick={(e) => {
                    e.stopPropagation();
                    setRenameD({
                      title: "グループ名を変更", initial: g.name,
                      cb: (nv) => {
                        setGroups((gs) => gs.map((x) => (x.id === g.id ? { ...x, name: nv } : x)));
                        advanceTut("rename", "addNote");
                      },
                    });
                  }} style={{ opacity: 0.75, display: "inline-flex" }}><UIcon name="edit" size={13} color={TOP_SUBTLE} /></span>
                )}
              </button>
            );
          })}
          <button onClick={() => setDialog({ type: "group", name: "" })} style={{
            border: `1.5px dashed ${TOP_BORDER}`, background: "none", color: TOP_SUBTLE,
            borderRadius: 999, padding: "8px 15px", fontSize: 13, cursor: "pointer",
          }}>＋</button>
        </div>

        {/* ノート(プレビュー付きグリッド) */}
        {selG ? (
          <div style={{
            display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 180px), 1fr))",
            gap: 14, marginTop: 30,
          }}>
            <button onClick={() => setDialog({ type: "note", name: defaultNoteName() })}
              className={tut === "addNote" ? "tut-glow" : undefined}
              style={{
              minHeight: 140, borderRadius: 20, border: `2px dashed ${TOP_BORDER}`, background: "rgba(255,255,255,0.12)",
              color: TOP_INK, fontSize: 12.5, cursor: "pointer", display: "flex", flexDirection: "column",
              alignItems: "center", justifyContent: "center", gap: 6, letterSpacing: 1, fontWeight: 600,
            }}>
              <span style={{ fontSize: 26, color: TOP_INK }}>＋</span>
              新しいノート
            </button>
            {selG.notes.map((n, ni) => (
              <div key={n.id}
                className={tut === "openNote" && ni === 0 ? "tut-glow" : undefined}
                onClick={() => { setOpenNote({ groupId: selG.id, noteId: n.id }); advanceTut("openNote", "text"); }} style={{
                background: TOP_SURFACE, borderRadius: 20, padding: 10, cursor: "pointer",
                border: `1.5px solid ${TOP_BORDER}`, boxShadow: "0 6px 18px rgba(40,42,48,0.22)",
              }}>
                <MiniPreview cards={n.cards} />
                <div style={{ display: "flex", alignItems: "center", marginTop: 8, gap: 6 }}>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{
                      fontWeight: 600, fontSize: 12.5, color: TOP_INK,
                      overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
                    }}>{n.name}</div>
                    <div style={{ fontSize: 10, color: TOP_SUBTLE, marginTop: 2 }}>
                      カード {n.cards.filter((c) => !c.parentId).length} 枚
                    </div>
                  </div>
                  <span onClick={(e) => {
                    e.stopPropagation();
                    setRenameD({
                      title: "ノート名を変更", initial: n.name,
                      cb: (nv) => setGroups((gs) => gs.map((g) => (g.id !== selG.id ? g : { ...g, notes: g.notes.map((x) => (x.id === n.id ? { ...x, name: nv } : x)) }))),
                    });
                  }} style={{ color: TOP_SUBTLE, padding: "2px 4px", fontSize: 14 }}>⋯</span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={{ marginTop: 50, textAlign: "center", color: TOP_SUBTLE, fontSize: 13 }}>
            「＋」からグループを作りましょう
          </div>
        )}

        <div style={{ marginTop: 50, textAlign: "center", color: TOP_SUBTLE, fontSize: 10, letterSpacing: 3, fontFamily: "'Hiragino Sans','Noto Sans JP',sans-serif", fontWeight: 700 }}>
          onote
        </div>
        <div style={{ textAlign: "center", marginTop: 10 }}>
          <button onClick={() => setTut("rename")} style={{ border: "none", background: "none", color: TOP_SUBTLE, fontSize: 11, cursor: "pointer", letterSpacing: 1 }}>
            ？ 使い方をもう一度見る
          </button>
        </div>
      </div>

      <TutStyle />
      {tut === "rename" && (
        <TutBubble no={1} title="グループ名を変えてみよう"
          desc={<>光っているチップの「✎」をタップして、すきな名前に変えてみよう。</>}
          onSkip={endTut} style={{ bottom: 26 }} />
      )}
      {tut === "addNote" && (
        <TutBubble no={2} title="ノートを作ろう"
          desc={<>点線の「＋ 新しいノート」をタップ。名前はそのままでもOK!</>}
          onSkip={endTut} style={{ bottom: 26 }} />
      )}
      {tut === "openNote" && (
        <TutBubble no={3} title="ノートを開こう"
          desc={<>できたノートのタイルをタップして、キャンバスへ。</>}
          onSkip={endTut} style={{ bottom: 26 }} />
      )}

      {/* 作成ダイアログ */}
      {dialog && (
        <PromptDialog
          title={dialog.type === "note" ? "ノートの名前を入力してください" : "グループ名を入力してください"}
          initial={dialog.name}
          onOk={(name) => {
            if (dialog.type === "group") setGroups((gs) => [...gs, { id: uid(), name, notes: [] }]);
            else {
              setGroups((gs) => gs.map((g) => (g.id !== effSel ? g : { ...g, notes: [...g.notes, { id: uid(), name, cards: [] }] })));
              advanceTut("addNote", "openNote");
            }
          }}
          onClose={() => setDialog(null)} />
      )}
      {renameD && (
        <PromptDialog title={renameD.title} initial={renameD.initial}
          onOk={renameD.cb} onClose={() => setRenameD(null)} />
      )}

      {/* 設定パネル */}
      {settingsOpen && (
        <div onClick={() => setSettingsOpen(false)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", zIndex: 90, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
          <div onClick={(e) => e.stopPropagation()} style={{ background: SURFACE, borderRadius: 22, width: 320, maxHeight: "88vh", overflowY: "auto", padding: 20, boxShadow: SHADOW_POP, border: `1px solid ${BORDER}` }}>
            <div style={{ fontSize: 16, fontWeight: 700, color: INK, textAlign: "center", marginBottom: 16 }}>設定</div>

            {/* 背景 */}
            <div style={{ fontSize: 12, color: SUBTLE, marginBottom: 8, letterSpacing: 1 }}>トップ画面の背景</div>
            <div style={{
              height: 110, borderRadius: 14, marginBottom: 12, border: `1px solid ${BORDER}`,
              background: bgImage ? `url(${bgImage}) center/cover no-repeat` : TOP_BG,
              display: "flex", alignItems: "flex-end", justifyContent: "center",
            }}>
              {!bgImage && <span style={{ color: SUBTLE, fontSize: 12, paddingBottom: 8 }}>背景なし(グレー)</span>}
            </div>
            <button onClick={() => bgInput.current.click()} style={{
              width: "100%", padding: "11px 0", marginBottom: 8, borderRadius: 12, border: "none",
              background: ACCENT_DEEP, color: "#15171b", fontSize: 14, fontWeight: 700, cursor: "pointer",
            }}>画像を選んで背景にする</button>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={() => setBgImage(DEFAULT_BG)} style={{
                flex: 1, padding: "9px 0", borderRadius: 12, border: `1px solid ${BORDER}`,
                background: SURFACE_2, color: INK, fontSize: 12, cursor: "pointer",
              }}>デフォルトに戻す</button>
              <button onClick={() => setBgImage("")} style={{
                flex: 1, padding: "9px 0", borderRadius: 12, border: `1px solid ${BORDER}`,
                background: SURFACE_2, color: INK, fontSize: 12, cursor: "pointer",
              }}>背景なし</button>
            </div>

            {/* 効果音・触覚 */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 18, padding: "12px 0", borderTop: `1px solid ${BORDER}` }}>
              <div>
                <div style={{ fontSize: 13, color: INK, fontWeight: 600 }}>効果音・バイブ</div>
                <div style={{ fontSize: 10, color: SUBTLE, marginTop: 2 }}>ボタンを押すとカツッと鳴ります</div>
              </div>
              <button onClick={() => { const v = !fxOn; setFxOn(v); setFxEnabled(v); if (v) feedback(); }}
                style={{
                  width: 50, height: 28, borderRadius: 14, border: "none", cursor: "pointer", position: "relative",
                  background: fxOn ? ACCENT_DEEP : "#555a63", transition: "background .15s", flexShrink: 0,
                }}>
                <span style={{
                  position: "absolute", top: 3, left: fxOn ? 25 : 3, width: 22, height: 22, borderRadius: 11,
                  background: "#fff", transition: "left .15s",
                }} />
              </button>
            </div>

            {/* About */}
            <div style={{ marginTop: 8, padding: "16px 0 4px", borderTop: `1px solid ${BORDER}` }}>
              <div style={{ fontSize: 15, fontWeight: 800, color: INK, letterSpacing: 1 }}>about onote</div>
              <div style={{ fontSize: 12, color: SUBTLE, lineHeight: 1.9, marginTop: 8 }}>
                お使いいただきありがとうございます。<br />
                ご意見ご要望があれば教えてくださると<br />ほんとうにうれしいです。
              </div>

              <a href="mailto:inuteddy12@example.com?subject=onote%20お問い合わせ" style={{ textDecoration: "none" }}>
                <div style={{ marginTop: 14, padding: "11px 14px", borderRadius: 12, background: SURFACE_2, border: `1px solid ${BORDER}`, cursor: "pointer" }}>
                  <div style={{ fontSize: 13, color: INK, fontWeight: 600 }}>お問い合わせ</div>
                  <div style={{ fontSize: 10, color: SUBTLE, marginTop: 2 }}>不具合報告・ご意見ご要望をください</div>
                </div>
              </a>

              <button onClick={() => showAppToast("公開後、App Storeのレビュー画面につながります")} style={{
                width: "100%", textAlign: "left", marginTop: 8, padding: "11px 14px", borderRadius: 12,
                background: SURFACE_2, border: `1px solid ${BORDER}`, cursor: "pointer",
              }}>
                <div style={{ fontSize: 13, color: INK, fontWeight: 600, display: "flex", alignItems: "center", gap: 7 }}><UIcon name="star" size={15} color={ACCENT} /> レビューで応援する</div>
                <div style={{ fontSize: 10, color: SUBTLE, marginTop: 2 }}>励みになります</div>
              </button>

              <button onClick={() => showAppToast("iCloud同期は準備中です(後ほど追加します)")} style={{
                width: "100%", textAlign: "left", marginTop: 8, padding: "11px 14px", borderRadius: 12,
                background: SURFACE_2, border: `1px solid ${BORDER}`, cursor: "pointer",
              }}>
                <div style={{ fontSize: 13, color: INK, fontWeight: 600, display: "flex", alignItems: "center", gap: 7 }}><UIcon name="cloud" size={15} color={ACCENT} /> データをiCloud同期</div>
                <div style={{ fontSize: 10, color: SUBTLE, marginTop: 2 }}>準備中</div>
              </button>

              <div style={{ marginTop: 8, padding: "11px 14px", borderRadius: 12, background: SURFACE_2, border: `1px solid ${BORDER}` }}>
                <div style={{ fontSize: 13, color: INK, fontWeight: 600 }}>other apps</div>
                <div style={{ fontSize: 10, color: SUBTLE, marginTop: 2 }}>後々追加します</div>
              </div>

              <a href="https://x.com/inuteddy12" target="_blank" rel="noopener noreferrer"
                style={{ display: "block", textAlign: "center", marginTop: 16, fontSize: 11, color: ACCENT, textDecoration: "none", letterSpacing: 1 }}>
                created by inu teddy
              </a>
            </div>

            <button onClick={() => setSettingsOpen(false)} style={{
              width: "100%", padding: "11px 0", marginTop: 12, borderRadius: 12, border: "none",
              background: "none", color: SUBTLE, fontSize: 13, cursor: "pointer",
            }}>閉じる</button>
          </div>
        </div>
      )}
      <input ref={bgInput} type="file" accept="image/*" style={{ display: "none" }}
        onChange={(e) => {
          const f = e.target.files[0];
          if (f) {
            const rd = new FileReader();
            rd.onload = () => setBgImage(rd.result);
            rd.readAsDataURL(f);
          }
          e.target.value = "";
        }} />

      {appToast && (
        <div style={{
          position: "fixed", bottom: 80, left: "50%", transform: "translateX(-50%)", zIndex: 999,
          background: "rgba(20,23,28,0.95)", color: "#fff", padding: "11px 22px", borderRadius: 20,
          fontSize: 13, boxShadow: "0 6px 20px rgba(0,0,0,0.5)", maxWidth: "85%", textAlign: "center",
        }}>{appToast}</div>
      )}

      <SaveBadge />
    </div>
  );
}

/* ============================================================
   ログイン画面 — perl rabbit風ミニマルUI
   ============================================================ */
function LoginGate({ onEnter }) {
  const [note, setNote] = useState("");
  return (
    <div style={{
      position: "fixed", inset: 0, overflow: "auto",
      fontFamily: "'Hiragino Sans','Noto Sans JP',sans-serif",
      background: `linear-gradient(rgba(154,154,157,0.6), rgba(154,154,157,0.72)), url(${DEFAULT_BG}) center/cover no-repeat`,
    }}>
      <div style={{ minHeight: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "48px 26px", boxSizing: "border-box" }}>


        <div style={{
          marginTop: 40, fontSize: 40, color: TOP_INK, fontFamily: "'Hiragino Sans','Noto Sans JP',sans-serif", fontWeight: 800,
          letterSpacing: "0.14em", textIndent: "0.14em",
        }}>onote</div>

        <div style={{
          marginTop: 14, fontSize: 12, color: TOP_SUBTLE, letterSpacing: "0.32em", textIndent: "0.32em",
          display: "flex", alignItems: "center", gap: 10,
        }}>
          <span style={{ letterSpacing: 0, textIndent: 0 }}>〜</span>
          CARDS ON MY CANVAS
          <span style={{ letterSpacing: 0, textIndent: 0 }}>〜</span>
        </div>

        <div style={{ width: "min(560px, 92%)", height: 1, background: TOP_BORDER, margin: "44px 0 52px" }} />

        <button onClick={onEnter} style={{
          width: "min(560px, 100%)", padding: "19px 0", border: "none", borderRadius: 999,
          background: TOP_ACTIVE, color: "#f3f3f4", fontSize: 17, fontWeight: 700, letterSpacing: 2,
          cursor: "pointer", boxShadow: "0 6px 16px rgba(40,42,48,0.3)",
        }}>＋ ログインなしで使用</button>

        <button onClick={() => setNote("プレビュー版ではGoogleログインは使えません。Firebase版で利用できます。")} style={{
          width: "min(560px, 100%)", padding: "16px 0", borderRadius: 999, marginTop: 14,
          background: TOP_SURFACE, color: TOP_INK, fontSize: 14, fontWeight: 600, letterSpacing: 1,
          border: `1px solid ${TOP_BORDER}`, cursor: "pointer", display: "flex",
          alignItems: "center", justifyContent: "center", gap: 8,
        }}>
          <span style={{
            width: 17, height: 17, borderRadius: 9, fontSize: 10, fontWeight: 800, color: "#fff",
            background: "conic-gradient(#4285f4 0 25%, #34a853 25% 50%, #fbbc05 50% 75%, #ea4335 75% 100%)",
            display: "flex", alignItems: "center", justifyContent: "center",
          }}>G</span>
          Googleでログイン
        </button>

        {note && <div style={{ fontSize: 11, color: TOP_ACTIVE, marginTop: 16, lineHeight: 1.7, textAlign: "center" }}>{note}</div>}

        <div style={{ fontSize: 12, color: TOP_SUBTLE, marginTop: 26, letterSpacing: 1, textAlign: "center" }}>
          すべて端末内だけで保存されます(どこにも送信されません)
        </div>
      </div>
    </div>
  );
}
